DECLARE
  CURSOR emp_cursor IS
    SELECT emp_id, first_name, last_name, salary
    FROM employees
    WHERE department_id = 10;
  v_emp emp_cursor%ROWTYPE;
BEGIN
  OPEN emp_cursor;
  LOOP
    FETCH emp_cursor INTO v_emp;
    EXIT WHEN emp_cursor%NOTFOUND;
    DBMS_OUTPUT.PUT_LINE(v_emp.first_name || ' ' || v_emp.last_name || ': ' || v_emp.salary);
  END LOOP;
  CLOSE emp_cursor;
END;

DECLARE
  TYPE emp_table_type IS TABLE OF employees%ROWTYPE
    INDEX BY PLS_INTEGER;
  v_employees emp_table_type;
BEGIN
  SELECT *
  BULK COLLECT INTO v_employees
  FROM employees
  WHERE department_id = 20;

  FOR i IN 1 .. v_employees.COUNT LOOP
    UPDATE employees
    SET salary = v_employees(i).salary * 1.10
    WHERE emp_id = v_employees(i).emp_id;
  END LOOP;
  COMMIT;
END;

DECLARE
  v_total_salary NUMBER := 0;
  v_emp_count    NUMBER := 0;
BEGIN
  SELECT SUM(salary), COUNT(*)
  INTO v_total_salary, v_emp_count
  FROM employees
  WHERE department_id = 30;

  IF v_emp_count = 0 THEN
    RAISE_APPLICATION_ERROR(-20001, 'No employees found in department 30');
  END IF;

  DBMS_OUTPUT.PUT_LINE('Avg Salary: ' || TO_CHAR(v_total_salary / v_emp_count));
EXCEPTION
  WHEN NO_DATA_FOUND THEN
    DBMS_OUTPUT.PUT_LINE('No data found.');
  WHEN OTHERS THEN
    DBMS_OUTPUT.PUT_LINE('Error: ' || SQLERRM);
END;

