CREATE OR REPLACE PROCEDURE update_salaries_by_dept(
  p_department_id IN NUMBER,
  p_raise_pct     IN NUMBER
) AS
  CURSOR c_emps IS
    SELECT emp_id, salary
    FROM employees
    WHERE department_id = p_department_id
    FOR UPDATE OF salary NOWAIT;
BEGIN
  FOR rec IN c_emps LOOP
    UPDATE employees
    SET salary = rec.salary * (1 + p_raise_pct / 100)
    WHERE CURRENT OF c_emps;
  END LOOP;
  COMMIT;
EXCEPTION
  WHEN OTHERS THEN
    ROLLBACK;
    RAISE;
END update_salaries_by_dept;

