                col('department_id') == department_id,
                col('salary') * (1 + raise_pct / 100)
            ).otherwise(col('salary'))
        )
        updated_df.write.mode('overwrite').saveAsTable('employees')
    except Exception as e:
        print(f'Transaction failed, changes not committed: {e}')
        raise
