DECLARE
  TYPE dept_salary_rec IS RECORD (
    department_id   NUMBER,
    total_salary    NUMBER,
    avg_salary      NUMBER,
    headcount       NUMBER
  );
  TYPE dept_salary_tab IS TABLE OF dept_salary_rec INDEX BY PLS_INTEGER;
  v_dept_stats dept_salary_tab;
  i PLS_INTEGER := 1;
BEGIN
  FOR rec IN (
    SELECT department_id,
           SUM(salary) AS total_salary,
           AVG(salary) AS avg_salary,
           COUNT(*) AS headcount
    FROM employees
    GROUP BY department_id
  ) LOOP
    v_dept_stats(i).department_id := rec.department_id;
    v_dept_stats(i).total_salary  := rec.total_salary;
    v_dept_stats(i).avg_salary    := rec.avg_salary;
    v_dept_stats(i).headcount     := rec.headcount;
    i := i + 1;
  END LOOP;
  FOR j IN 1 .. v_dept_stats.COUNT LOOP
    DBMS_OUTPUT.PUT_LINE('Dept: ' || v_dept_stats(j).department_id
      || ' Avg: ' || ROUND(v_dept_stats(j).avg_salary, 2));
  END LOOP;
END;

CREATE OR REPLACE FUNCTION get_dept_avg_salary(
  p_department_id IN NUMBER
) RETURN NUMBER AS
  v_avg_salary NUMBER;
BEGIN
  SELECT AVG(salary)
  INTO v_avg_salary
  FROM employees
  WHERE department_id = p_department_id;

  RETURN NVL(v_avg_salary, 0);
EXCEPTION
  WHEN NO_DATA_FOUND THEN
    RETURN 0;
END get_dept_avg_salary;

DECLARE
  TYPE emp_id_list IS TABLE OF employees.emp_id%TYPE;
  v_ids   emp_id_list;
  v_limit PLS_INTEGER := 100;
