DECLARE
  v_savepoint_name VARCHAR2(30) := 'before_updates';
BEGIN
  SAVEPOINT before_updates;

  UPDATE employees
  SET salary = salary * 1.05
  WHERE department_id = 10;

  UPDATE employees
  SET salary = salary * 1.08
  WHERE department_id = 20;

  IF SQL%ROWCOUNT = 0 THEN
    ROLLBACK TO before_updates;
    DBMS_OUTPUT.PUT_LINE('No rows updated, rolled back.');
  ELSE
    COMMIT;
    DBMS_OUTPUT.PUT_LINE('Updates committed.');
  END IF;
EXCEPTION
  WHEN OTHERS THEN
    ROLLBACK TO before_updates;
    DBMS_OUTPUT.PUT_LINE('Error: ' || SQLERRM);
END;

CREATE OR REPLACE PACKAGE emp_pkg AS
  FUNCTION calc_bonus(p_emp_id IN NUMBER) RETURN NUMBER;
  PROCEDURE apply_bonuses(p_dept_id IN NUMBER);
END emp_pkg;

CREATE OR REPLACE PACKAGE BODY emp_pkg AS
  FUNCTION calc_bonus(p_emp_id IN NUMBER) RETURN NUMBER AS
    v_salary   NUMBER;
    v_job_id   VARCHAR2(20);
    v_bonus    NUMBER := 0;
  BEGIN
    SELECT salary, job_id INTO v_salary, v_job_id
    FROM employees WHERE emp_id = p_emp_id;
    IF v_job_id LIKE 'SA%' THEN
      v_bonus := v_salary * 0.20;
    ELSIF v_job_id LIKE 'IT%' THEN
      v_bonus := v_salary * 0.15;
    ELSE
      v_bonus := v_salary * 0.10;
    END IF;
    RETURN v_bonus;
  EXCEPTION
    WHEN NO_DATA_FOUND THEN RETURN 0;
  END calc_bonus;

  PROCEDURE apply_bonuses(p_dept_id IN NUMBER) AS
  BEGIN
    UPDATE employees
    SET bonus = emp_pkg.calc_bonus(emp_id)
    WHERE department_id = p_dept_id;
    COMMIT;
  END apply_bonuses;
END emp_pkg;

