CREATE PROCEDURE GetEmployeesWithSalaryRange
    @MinSalary DECIMAL(18,2),
    @MaxSalary DECIMAL(18,2)
AS
BEGIN
    SELECT EmployeeID, FirstName, LastName, Salary
    FROM Employees
    WHERE Salary BETWEEN @MinSalary AND @MaxSalary
    ORDER BY Salary ASC;
END

CREATE PROCEDURE UpsertCustomer
    @CustomerID INT,
    @Name NVARCHAR(200),
    @Email NVARCHAR(200),
    @Phone NVARCHAR(50)
AS
BEGIN
    IF EXISTS (SELECT 1 FROM Customers WHERE CustomerID = @CustomerID)
    BEGIN
        UPDATE Customers
        SET Name = @Name, Email = @Email, Phone = @Phone, UpdatedAt = GETDATE()
        WHERE CustomerID = @CustomerID;
    END
    ELSE
    BEGIN
        INSERT INTO Customers (CustomerID, Name, Email, Phone, CreatedAt)
        VALUES (@CustomerID, @Name, @Email, @Phone, GETDATE());
    END
END

DECLARE
  CURSOR c_dept IS
    SELECT department_id, department_name FROM departments;
  CURSOR c_emp(p_dept_id NUMBER) IS
    SELECT employee_id, first_name, last_name, salary
    FROM employees
    WHERE department_id = p_dept_id;
  v_total_salary NUMBER := 0;
  v_emp_count    NUMBER := 0;
BEGIN
  FOR r_dept IN c_dept LOOP
    v_total_salary := 0;
    v_emp_count    := 0;
    FOR r_emp IN c_emp(r_dept.department_id) LOOP
      v_total_salary := v_total_salary + r_emp.salary;
      v_emp_count    := v_emp_count + 1;
    END LOOP;
    IF v_emp_count > 0 THEN
      INSERT INTO dept_salary_summary
        (department_id, department_name, avg_salary, emp_count)
      VALUES
        (r_dept.department_id, r_dept.department_name,
         v_total_salary / v_emp_count, v_emp_count);
    END IF;
  END LOOP;
  COMMIT;
EXCEPTION
  WHEN OTHERS THEN
    ROLLBACK;
    RAISE;
END;

DECLARE
  TYPE t_emp_rec IS RECORD (
    employee_id   employees.employee_id%TYPE,
    full_name     VARCHAR2(100),
    salary        employees.salary%TYPE,
    department_id employees.department_id%TYPE
  );
  TYPE t_emp_tab IS TABLE OF t_emp_rec INDEX BY PLS_INTEGER;
  l_emps     t_emp_tab;
  l_batch_sz CONSTANT PLS_INTEGER := 1000;
BEGIN
  SELECT employee_id,
         first_name || ' ' || last_name AS full_name,
         salary,
         department_id
  BULK COLLECT INTO l_emps
  FROM employees
  WHERE hire_date >= ADD_MONTHS(SYSDATE, -24);

  FORALL i IN 1 .. l_emps.COUNT
    INSERT INTO recent_hires
      (employee_id, full_name, salary, department_id)
    VALUES
      (l_emps(i).employee_id, l_emps(i).full_name,
       l_emps(i).salary,      l_emps(i).department_id);

  COMMIT;
EXCEPTION
  WHEN OTHERS THEN
    ROLLBACK;
    DBMS_OUTPUT.PUT_LINE('Error: ' || SQLERRM);
    RAISE;
END;

CREATE OR REPLACE PROCEDURE rebalance_inventory(
  p_warehouse_id IN  NUMBER,
  p_status       OUT VARCHAR2
) AS
  v_sql          VARCHAR2(4000);
  v_table_name   VARCHAR2(50);
  v_count        NUMBER;
BEGIN
  v_table_name := 'INV_WH_' || TO_CHAR(p_warehouse_id);

  v_sql := 'SELECT COUNT(*) FROM ' || v_table_name
        || ' WHERE qty_on_hand < reorder_point';
  EXECUTE IMMEDIATE v_sql INTO v_count;

  IF v_count > 0 THEN
    v_sql := 'UPDATE ' || v_table_name
          || ' SET replenish_flag = ''Y'', last_reviewed = SYSDATE'
          || ' WHERE qty_on_hand < reorder_point';
    EXECUTE IMMEDIATE v_sql;
    COMMIT;
    p_status := 'REPLENISHED:' || v_count;
  ELSE
    p_status := 'OK';
  END IF;
EXCEPTION
  WHEN OTHERS THEN
    ROLLBACK;
    p_status := 'ERROR:' || SQLERRM;
END;

DECLARE
  v_sql      CLOB;
  v_cur      SYS_REFCURSOR;
  v_col_list VARCHAR2(4000);
  v_row      employees%ROWTYPE;
BEGIN
  SELECT LISTAGG(column_name, ', ') WITHIN GROUP (ORDER BY column_id)
  INTO   v_col_list
  FROM   user_tab_columns
  WHERE  table_name = 'EMPLOYEES'
    AND  column_name NOT IN ('PASSWORD', 'SSN');

  v_sql := 'SELECT ' || v_col_list || ' FROM employees WHERE status = :1';

  OPEN v_cur FOR v_sql USING 'ACTIVE';
  LOOP
    FETCH v_cur INTO v_row;
    EXIT WHEN v_cur%NOTFOUND;
    -- process each row
    DBMS_OUTPUT.PUT_LINE(v_row.employee_id || ': ' || v_row.last_name);
  END LOOP;
  CLOSE v_cur;
END;

DECLARE
  TYPE t_id_list IS TABLE OF NUMBER;
  l_ids      t_id_list;
  l_errors   VARCHAR2(32767);
  v_err_cnt  NUMBER := 0;
BEGIN
  SELECT order_id
  BULK COLLECT INTO l_ids
  FROM orders
  WHERE order_status = 'PENDING'
    AND order_date < SYSDATE - 30;

  FORALL i IN 1 .. l_ids.COUNT SAVE EXCEPTIONS
    UPDATE orders
    SET    order_status = 'CANCELLED',
           cancelled_at = SYSTIMESTAMP
    WHERE  order_id = l_ids(i);

  COMMIT;
EXCEPTION
  WHEN OTHERS THEN
    IF SQL%BULK_EXCEPTIONS.COUNT > 0 THEN
      FOR j IN 1 .. SQL%BULK_EXCEPTIONS.COUNT LOOP
        l_errors := l_errors
          || 'Row ' || SQL%BULK_EXCEPTIONS(j).ERROR_INDEX
          || ': '   || SQLERRM(-SQL%BULK_EXCEPTIONS(j).ERROR_CODE)
          || CHR(10);
        v_err_cnt := v_err_cnt + 1;
      END LOOP;
      DBMS_OUTPUT.PUT_LINE(v_err_cnt || ' errors: ' || l_errors);
      COMMIT; -- commit successful rows
    ELSE
      ROLLBACK;
      RAISE;
    END IF;
END;

CREATE OR REPLACE PACKAGE audit_pkg AS
  PROCEDURE log_change(
    p_table_name IN VARCHAR2,
    p_operation  IN VARCHAR2,
    p_row_id     IN VARCHAR2,
    p_old_val    IN CLOB DEFAULT NULL,
    p_new_val    IN CLOB DEFAULT NULL
  );
  FUNCTION get_audit_trail(
    p_table_name IN VARCHAR2,
    p_from_date  IN DATE
  ) RETURN SYS_REFCURSOR;
END audit_pkg;
/
CREATE OR REPLACE PACKAGE BODY audit_pkg AS
  PROCEDURE log_change(p_table_name IN VARCHAR2, p_operation IN VARCHAR2,
                       p_row_id IN VARCHAR2, p_old_val IN CLOB DEFAULT NULL,
                       p_new_val IN CLOB DEFAULT NULL) AS
    PRAGMA AUTONOMOUS_TRANSACTION;
  BEGIN
    INSERT INTO audit_log(table_name, operation, row_id, old_value, new_value, changed_at, changed_by)
    VALUES (p_table_name, p_operation, p_row_id, p_old_val, p_new_val, SYSTIMESTAMP, SYS_CONTEXT('USERENV','SESSION_USER'));
    COMMIT;
  EXCEPTION
    WHEN OTHERS THEN NULL;
  END;

  FUNCTION get_audit_trail(p_table_name IN VARCHAR2, p_from_date IN DATE)
  RETURN SYS_REFCURSOR AS
    v_cur SYS_REFCURSOR;
  BEGIN
    OPEN v_cur FOR
      SELECT * FROM audit_log
      WHERE table_name = p_table_name
        AND TRUNC(changed_at) >= p_from_date
      ORDER BY changed_at;
    RETURN v_cur;
  END;
END audit_pkg;

DECLARE
  v_xml    XMLTYPE;
  v_doc    DBMS_XMLDOM.DOMDocument;
  v_root   DBMS_XMLDOM.DOMElement;
  v_emp    DBMS_XMLDOM.DOMElement;
  v_node   DBMS_XMLDOM.DOMNode;
  CURSOR c_emp IS
    SELECT employee_id, first_name, last_name, salary, department_id
    FROM   employees
    WHERE  department_id = 10;
BEGIN
  v_doc  := DBMS_XMLDOM.NEWDOMDOCUMENT;
  v_root := DBMS_XMLDOM.CREATEELEMENT(v_doc, 'Employees');
  v_node := DBMS_XMLDOM.APPENDCHILD(
              DBMS_XMLDOM.MAKENODE(v_doc),
              DBMS_XMLDOM.MAKENODE(v_root));

  FOR r IN c_emp LOOP
    v_emp := DBMS_XMLDOM.CREATEELEMENT(v_doc, 'Employee');
    DBMS_XMLDOM.SETATTRIBUTE(v_emp, 'id', TO_CHAR(r.employee_id));
    DBMS_XMLDOM.SETATTRIBUTE(v_emp, 'name', r.first_name || ' ' || r.last_name);
    DBMS_XMLDOM.SETATTRIBUTE(v_emp, 'salary', TO_CHAR(r.salary));
    v_node := DBMS_XMLDOM.APPENDCHILD(
                DBMS_XMLDOM.MAKENODE(v_root),
                DBMS_XMLDOM.MAKENODE(v_emp));
  END LOOP;

  SELECT XMLTYPE(DBMS_XMLDOM.GETXMLTYPE(v_doc).GETCLOBVAL())
  INTO   v_xml FROM DUAL;
  DBMS_XMLDOM.FREEDOCUMENT(v_doc);

  INSERT INTO xml_output(payload, created_at)
  VALUES (v_xml, SYSTIMESTAMP);
  COMMIT;
END;

CREATE OR REPLACE TRIGGER trg_orders_audit
AFTER INSERT OR UPDATE OR DELETE ON orders
FOR EACH ROW
DECLARE
  v_op VARCHAR2(6);
BEGIN
  IF INSERTING THEN
    v_op := 'INSERT';
  ELSIF UPDATING THEN
    v_op := 'UPDATE';
  ELSE
    v_op := 'DELETE';
  END IF;

  INSERT INTO orders_audit(
    audit_id, order_id, operation,
    old_status, new_status,
    old_amount, new_amount,
    changed_by, changed_at
  ) VALUES (
    orders_audit_seq.NEXTVAL,
    COALESCE(:NEW.order_id, :OLD.order_id),
    v_op,
    :OLD.order_status, :NEW.order_status,
    :OLD.total_amount, :NEW.total_amount,
    USER, SYSTIMESTAMP
  );
EXCEPTION
  WHEN OTHERS THEN
    NULL; -- swallow audit errors, never block DML
END;

DECLARE
  v_ddl     VARCHAR2(32767);
  v_cnt     NUMBER;
  v_obj     VARCHAR2(128);
  TYPE t_obj_list IS TABLE OF VARCHAR2(128);
  l_stale   t_obj_list := t_obj_list();
BEGIN
  -- Find all materialized views older than 1 hour
  FOR r IN (
    SELECT mview_name
    FROM   user_mviews
    WHERE  last_refresh_date < SYSDATE - 1/24
      AND  staleness IN ('STALE', 'UNKNOWN')
  ) LOOP
    l_stale.EXTEND;
    l_stale(l_stale.LAST) := r.mview_name;
  END LOOP;

  IF l_stale.COUNT = 0 THEN
    DBMS_OUTPUT.PUT_LINE('All MVs fresh.');
    RETURN;
  END IF;

  FOR i IN 1 .. l_stale.COUNT LOOP
    BEGIN
      DBMS_MVIEW.REFRESH(
        list          => l_stale(i),
        method        => 'F', -- fast refresh
        atomic_refresh => FALSE
      );
      DBMS_OUTPUT.PUT_LINE('Refreshed: ' || l_stale(i));
    EXCEPTION
      WHEN OTHERS THEN
        DBMS_MVIEW.REFRESH(
          list          => l_stale(i),
          method        => 'C', -- complete fallback
          atomic_refresh => FALSE
        );
        DBMS_OUTPUT.PUT_LINE('Complete refresh fallback: ' || l_stale(i));
    END;
  END LOOP;
END;

CREATE PROCEDURE usp_SalesRollup
    @StartDate DATE,
    @EndDate   DATE
AS
BEGIN
    SET NOCOUNT ON;

    BEGIN TRY
        BEGIN TRANSACTION;

        TRUNCATE TABLE dbo.sales_rollup;

        WITH daily_sales AS (
            SELECT
                s.store_id,
                s.product_id,
                CAST(s.sale_date AS DATE)          AS sale_day,
                SUM(s.quantity)                    AS total_qty,
                SUM(s.quantity * s.unit_price)     AS total_revenue
            FROM dbo.sales s
            WHERE s.sale_date BETWEEN @StartDate AND @EndDate
            GROUP BY s.store_id, s.product_id, CAST(s.sale_date AS DATE)
        ),
        ranked AS (
            SELECT *,
                RANK() OVER (PARTITION BY store_id ORDER BY total_revenue DESC) AS revenue_rank,
                LAG(total_revenue)  OVER (PARTITION BY store_id, product_id ORDER BY sale_day) AS prev_day_revenue,
                SUM(total_revenue)  OVER (PARTITION BY store_id ORDER BY sale_day ROWS BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW) AS running_total
            FROM daily_sales
        )
        INSERT INTO dbo.sales_rollup
        SELECT store_id, product_id, sale_day,
               total_qty, total_revenue, revenue_rank,
               prev_day_revenue, running_total
        FROM   ranked;

        COMMIT TRANSACTION;
    END TRY
    BEGIN CATCH
        ROLLBACK TRANSACTION;
        THROW;
    END CATCH;
END;

CREATE PROCEDURE usp_ProcessEmployeeBonuses
    @FiscalYear INT
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @dept_id   INT;
    DECLARE @dept_name VARCHAR(100);
    DECLARE @avg_perf  DECIMAL(5,2);

    DECLARE dept_cursor CURSOR FAST_FORWARD FOR
        SELECT department_id, department_name
        FROM   hr.departments
        WHERE  active = 1;

    OPEN dept_cursor;
    FETCH NEXT FROM dept_cursor INTO @dept_id, @dept_name;

    WHILE @@FETCH_STATUS = 0
    BEGIN
        SELECT @avg_perf = AVG(performance_score)
        FROM   hr.performance_reviews
        WHERE  department_id = @dept_id
          AND  fiscal_year   = @FiscalYear;

        UPDATE hr.employees
        SET    bonus_amount = CASE
                   WHEN performance_score >= @avg_perf * 1.2 THEN salary * 0.15
                   WHEN performance_score >= @avg_perf        THEN salary * 0.10
                   ELSE salary * 0.05
               END,
               bonus_year   = @FiscalYear
        WHERE  department_id = @dept_id
          AND  fiscal_year   = @FiscalYear;

        FETCH NEXT FROM dept_cursor INTO @dept_id, @dept_name;
    END;

    CLOSE dept_cursor;
    DEALLOCATE dept_cursor;
END;

CREATE PROCEDURE usp_PartitionedArchive
    @ArchiveBeforeDate DATE,
    @RowsArchived      INT OUTPUT
AS
BEGIN
    SET NOCOUNT ON;
    SET @RowsArchived = 0;

    DECLARE @BatchSize  INT = 10000;
    DECLARE @Rows       INT = 1;

    WHILE @Rows > 0
    BEGIN
        BEGIN TRY
            BEGIN TRANSACTION;

            INSERT INTO archive.orders (order_id, customer_id, order_date, total_amount, archived_at)
            SELECT TOP (@BatchSize)
                   order_id, customer_id, order_date, total_amount, GETDATE()
            FROM   dbo.orders
            WHERE  order_date < @ArchiveBeforeDate
              AND  order_status = 'COMPLETED';

            SET @Rows = @@ROWCOUNT;
            SET @RowsArchived = @RowsArchived + @Rows;

            DELETE FROM dbo.orders
            WHERE order_id IN (
                SELECT order_id FROM archive.orders
                WHERE archived_at >= CAST(GETDATE() AS DATE)
                  AND order_date < @ArchiveBeforeDate
            );

            COMMIT TRANSACTION;
        END TRY
        BEGIN CATCH
            ROLLBACK TRANSACTION;
            THROW;
        END CATCH;
    END;
END;

CREATE PROCEDURE usp_DynamicPivotSalesReport
    @Year INT
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @cols    NVARCHAR(MAX);
    DECLARE @sql     NVARCHAR(MAX);

    SELECT @cols = STRING_AGG(
        QUOTENAME(DATENAME(MONTH, DATEFROMPARTS(@Year, month_num, 1))),
        ', '
    ) WITHIN GROUP (ORDER BY month_num)
    FROM (
        SELECT DISTINCT MONTH(sale_date) AS month_num
        FROM dbo.sales
        WHERE YEAR(sale_date) = @Year
    ) m;

    SET @sql = N'
        SELECT store_id, product_id, ' + @cols + N'
        FROM (
            SELECT store_id, product_id,
                   DATENAME(MONTH, sale_date) AS sale_month,
                   SUM(quantity * unit_price)  AS revenue
            FROM dbo.sales
            WHERE YEAR(sale_date) = ' + CAST(@Year AS NVARCHAR) + N'
            GROUP BY store_id, product_id, DATENAME(MONTH, sale_date)
        ) src
        PIVOT (
            SUM(revenue)
            FOR sale_month IN (' + @cols + N')
        ) pvt
        ORDER BY store_id, product_id;';

    EXEC sp_executesql @sql;
END;

CREATE PROCEDURE usp_IncrementalETL
    @SourceTable  NVARCHAR(128),
    @TargetTable  NVARCHAR(128),
    @WatermarkCol NVARCHAR(128)
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @LastWatermark DATETIME2;
    DECLARE @NewWatermark  DATETIME2 = SYSUTCDATETIME();
    DECLARE @sql           NVARCHAR(MAX);

    SELECT @LastWatermark = last_loaded_at
    FROM   etl_watermarks
    WHERE  source_table = @SourceTable;

    IF @LastWatermark IS NULL SET @LastWatermark = '1900-01-01';

    SET @sql = N'INSERT INTO ' + QUOTENAME(@TargetTable) + N'
        SELECT * FROM ' + QUOTENAME(@SourceTable) + N'
        WHERE ' + QUOTENAME(@WatermarkCol) + N' > @lwm
          AND ' + QUOTENAME(@WatermarkCol) + N' <= @nwm';

    EXEC sp_executesql @sql,
         N'@lwm DATETIME2, @nwm DATETIME2',
         @lwm = @LastWatermark, @nwm = @NewWatermark;

    MERGE etl_watermarks AS tgt
    USING (SELECT @SourceTable AS source_table, @NewWatermark AS last_loaded_at) AS src
        ON tgt.source_table = src.source_table
    WHEN MATCHED THEN
        UPDATE SET tgt.last_loaded_at = src.last_loaded_at
    WHEN NOT MATCHED THEN
        INSERT (source_table, last_loaded_at)
        VALUES (src.source_table, src.last_loaded_at);
END;

CREATE PROCEDURE usp_RetryableDataLoad
    @SourceSchema NVARCHAR(50),
    @TargetSchema NVARCHAR(50),
    @MaxRetries   INT = 3
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @Attempt   INT = 0;
    DECLARE @Success   BIT = 0;
    DECLARE @ErrMsg    NVARCHAR(2048);
    DECLARE @RowsLoaded INT;

    WHILE @Attempt < @MaxRetries AND @Success = 0
    BEGIN
        SET @Attempt = @Attempt + 1;
        BEGIN TRY
            BEGIN TRANSACTION;

            DELETE FROM staging.load_errors
            WHERE schema_name = @TargetSchema;

            INSERT INTO fact.sales_summary
            SELECT
                fs.store_id,
                fs.product_id,
                SUM(fs.revenue)         AS total_revenue,
                COUNT(*)                AS transaction_count,
                MAX(fs.sale_date)       AS last_sale_date,
                GETDATE()               AS loaded_at
            FROM staging.fact_sales fs
            WHERE fs.is_valid = 1
              AND fs.schema_tag = @SourceSchema
            GROUP BY fs.store_id, fs.product_id
            HAVING SUM(fs.revenue) > 0;

            SET @RowsLoaded = @@ROWCOUNT;

            INSERT INTO etl_audit_log (schema_name, rows_loaded, attempt, loaded_at)
            VALUES (@TargetSchema, @RowsLoaded, @Attempt, GETDATE());

            COMMIT TRANSACTION;
            SET @Success = 1;
        END TRY
        BEGIN CATCH
            ROLLBACK TRANSACTION;
            SET @ErrMsg = ERROR_MESSAGE();

            INSERT INTO staging.load_errors (schema_name, attempt, error_msg, occurred_at)
            VALUES (@TargetSchema, @Attempt, @ErrMsg, GETDATE());

            IF @Attempt = @MaxRetries
                THROW;

            WAITFOR DELAY '00:00:05';
        END CATCH;
    END;
END;

CREATE PROCEDURE usp_DynamicPivotSalesReport
    @StartDate DATE,
    @EndDate DATE,
    @GroupByColumn NVARCHAR(50)
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @Columns NVARCHAR(MAX);
    DECLARE @SQL NVARCHAR(MAX);
    DECLARE @TempTable NVARCHAR(100) = '##DynamicPivot_' + CAST(@@SPID AS VARCHAR);

    SELECT @Columns = STRING_AGG(QUOTENAME(Region), ',') WITHIN GROUP (ORDER BY Region)
    FROM (SELECT DISTINCT Region FROM Sales WHERE SaleDate BETWEEN @StartDate AND @EndDate) r;

    SET @SQL = N'
    SELECT * FROM (
        SELECT 
            ' + @GroupByColumn + ',
            Region,
            Amount
        FROM Sales
        WHERE SaleDate BETWEEN @StartDate AND @EndDate
    ) src
    PIVOT (
        SUM(Amount)
        FOR Region IN (' + @Columns + ')
    ) pvt
    ORDER BY ' + @GroupByColumn;

    EXEC sp_executesql @SQL, 
        N'@StartDate DATE, @EndDate DATE', 
        @StartDate, @EndDate;
END

CREATE PROCEDURE usp_InventoryReorderWithCursor
AS
BEGIN
    SET NOCOUNT ON;
    BEGIN TRY
        BEGIN TRANSACTION;

        DECLARE @ProductId INT, @CurrentStock INT, @ReorderLevel INT, @ReorderQty INT;
        DECLARE @OrderId INT;

        DECLARE reorder_cursor CURSOR FAST_FORWARD FOR
            SELECT p.ProductId, i.QuantityOnHand, p.ReorderLevel, p.ReorderQuantity
            FROM Products p
            JOIN Inventory i ON p.ProductId = i.ProductId
            WHERE i.QuantityOnHand <= p.ReorderLevel
            AND p.IsActive = 1
            ORDER BY (p.ReorderLevel - i.QuantityOnHand) DESC;

        OPEN reorder_cursor;
        FETCH NEXT FROM reorder_cursor INTO @ProductId, @CurrentStock, @ReorderLevel, @ReorderQty;

        WHILE @@FETCH_STATUS = 0
        BEGIN
            INSERT INTO PurchaseOrders (ProductId, Quantity, OrderDate, Status)
            VALUES (@ProductId, @ReorderQty, GETDATE(), 'PENDING');

            SET @OrderId = SCOPE_IDENTITY();

            INSERT INTO AuditLog (Action, EntityId, Details, CreatedAt)
            VALUES ('REORDER', @OrderId, 
                    'Product ' + CAST(@ProductId AS VARCHAR) + ' reordered. Stock: ' + CAST(@CurrentStock AS VARCHAR),
                    GETDATE());

            FETCH NEXT FROM reorder_cursor INTO @ProductId, @CurrentStock, @ReorderLevel, @ReorderQty;
        END

        CLOSE reorder_cursor;
        DEALLOCATE reorder_cursor;

        COMMIT TRANSACTION;
    END TRY
    BEGIN CATCH
        IF CURSOR_STATUS('global', 'reorder_cursor') >= 0
        BEGIN
            CLOSE reorder_cursor;
            DEALLOCATE reorder_cursor;
        END
        ROLLBACK TRANSACTION;
        THROW;
    END CATCH
END

CREATE PROCEDURE usp_SCD2CustomerUpdate
    @CustomerId INT,
    @NewEmail NVARCHAR(255),
    @NewAddress NVARCHAR(500),
    @NewSegment NVARCHAR(50),
    @EffectiveDate DATE = NULL
AS
BEGIN
    SET NOCOUNT ON;
    SET @EffectiveDate = ISNULL(@EffectiveDate, CAST(GETDATE() AS DATE));

    BEGIN TRANSACTION;
    BEGIN TRY
        -- Expire current active record
        UPDATE CustomerDim
        SET ExpiryDate = DATEADD(DAY, -1, @EffectiveDate),
            IsCurrent = 0,
            UpdatedAt = GETDATE()
        WHERE CustomerId = @CustomerId
        AND IsCurrent = 1;

        -- Insert new version
        INSERT INTO CustomerDim (
            CustomerId, Email, Address, Segment,
            EffectiveDate, ExpiryDate, IsCurrent,
            Version, CreatedAt
        )
        SELECT 
            @CustomerId, @NewEmail, @NewAddress, @NewSegment,
            @EffectiveDate, '9999-12-31', 1,
            ISNULL(MAX(Version), 0) + 1,
            GETDATE()
        FROM CustomerDim
        WHERE CustomerId = @CustomerId;

        COMMIT TRANSACTION;
    END TRY
    BEGIN CATCH
        ROLLBACK TRANSACTION;
        INSERT INTO ErrorLog (ProcedureName, ErrorMessage, ErrorTime)
        VALUES ('usp_SCD2CustomerUpdate', ERROR_MESSAGE(), GETDATE());
        THROW;
    END CATCH
END

CREATE PROCEDURE usp_DeadlockSafeTransfer
    @FromAccountId INT,
    @ToAccountId INT,
    @Amount DECIMAL(18,2),
    @MaxRetries INT = 3
AS
BEGIN
    SET NOCOUNT ON;
    DECLARE @Retries INT = 0;
    DECLARE @Success BIT = 0;

    WHILE @Retries < @MaxRetries AND @Success = 0
    BEGIN
        BEGIN TRY
            BEGIN TRANSACTION;

            -- Lock in consistent order to prevent deadlock
            DECLARE @MinId INT = CASE WHEN @FromAccountId < @ToAccountId THEN @FromAccountId ELSE @ToAccountId END;
            DECLARE @MaxId INT = CASE WHEN @FromAccountId < @ToAccountId THEN @ToAccountId ELSE @FromAccountId END;

            SELECT AccountId, Balance
            FROM Accounts WITH (UPDLOCK, ROWLOCK)
            WHERE AccountId IN (@MinId, @MaxId);

            IF (SELECT Balance FROM Accounts WHERE AccountId = @FromAccountId) < @Amount
                RAISERROR('Insufficient funds', 16, 1);

            UPDATE Accounts SET Balance = Balance - @Amount WHERE AccountId = @FromAccountId;
            UPDATE Accounts SET Balance = Balance + @Amount WHERE AccountId = @ToAccountId;

            INSERT INTO Transactions (FromAccountId, ToAccountId, Amount, TransactionDate, Status)
            VALUES (@FromAccountId, @ToAccountId, @Amount, GETDATE(), 'COMPLETED');

            COMMIT TRANSACTION;
            SET @Success = 1;
        END TRY
        BEGIN CATCH
            IF @@TRANCOUNT > 0 ROLLBACK TRANSACTION;
            IF ERROR_NUMBER() = 1205 -- Deadlock
            BEGIN
                SET @Retries = @Retries + 1;
                WAITFOR DELAY '00:00:00.1';
            END
            ELSE THROW;
        END CATCH
    END

    IF @Success = 0
        RAISERROR('Transaction failed after max retries', 16, 1);
END

CREATE PROCEDURE usp_AdaptiveQueryStats
    @TableName NVARCHAR(128),
    @SchemaName NVARCHAR(128) = 'dbo',
    @IncludeHistogram BIT = 0
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @SQL NVARCHAR(MAX);
    DECLARE @ObjectId INT;
    DECLARE @ColName NVARCHAR(128);
    DECLARE @StatsName NVARCHAR(128);

    SELECT @ObjectId = OBJECT_ID(@SchemaName + '.' + @TableName);

    IF @ObjectId IS NULL
        RAISERROR('Table not found', 16, 1);

    CREATE TABLE #ColumnStats (
        ColumnName NVARCHAR(128),
        DataType NVARCHAR(50),
        NullCount BIGINT,
        DistinctCount BIGINT,
        MinValue SQL_VARIANT,
        MaxValue SQL_VARIANT,
        AvgLength FLOAT
    );

    DECLARE col_cursor CURSOR FOR
        SELECT c.name, t.name
        FROM sys.columns c
        JOIN sys.types t ON c.user_type_id = t.user_type_id
        WHERE c.object_id = @ObjectId;

    OPEN col_cursor;
    FETCH NEXT FROM col_cursor INTO @ColName, @DataType;

    WHILE @@FETCH_STATUS = 0
    BEGIN
        SET @SQL = N'INSERT INTO #ColumnStats SELECT ''' + @ColName + ''', ''' + @DataType + ''',
            SUM(CASE WHEN ' + QUOTENAME(@ColName) + ' IS NULL THEN 1 ELSE 0 END),
            COUNT(DISTINCT ' + QUOTENAME(@ColName) + '),
            MIN(CAST(' + QUOTENAME(@ColName) + ' AS SQL_VARIANT)),
            MAX(CAST(' + QUOTENAME(@ColName) + ' AS SQL_VARIANT)),
            AVG(LEN(CAST(' + QUOTENAME(@ColName) + ' AS NVARCHAR(MAX))))
            FROM ' + QUOTENAME(@SchemaName) + '.' + QUOTENAME(@TableName);
        EXEC(@SQL);
        FETCH NEXT FROM col_cursor INTO @ColName, @DataType;
    END
    CLOSE col_cursor;
    DEALLOCATE col_cursor;

    SELECT * FROM #ColumnStats;
    DROP TABLE #ColumnStats;
END

CREATE PROCEDURE usp_GraphShortestPath
    @SourceNodeId INT,
    @TargetNodeId INT
AS
BEGIN
    SET NOCOUNT ON;

    CREATE TABLE #Queue (
        NodeId INT,
        Distance INT,
        PathStr NVARCHAR(MAX),
        Visited BIT DEFAULT 0
    );

    INSERT INTO #Queue VALUES (@SourceNodeId, 0, CAST(@SourceNodeId AS NVARCHAR), 0);

    DECLARE @CurrentNode INT, @CurrentDist INT, @CurrentPath NVARCHAR(MAX);

    WHILE EXISTS (SELECT 1 FROM #Queue WHERE Visited = 0)
    BEGIN
        SELECT TOP 1 @CurrentNode = NodeId, @CurrentDist = Distance, @CurrentPath = PathStr
        FROM #Queue WHERE Visited = 0
        ORDER BY Distance ASC;

        IF @CurrentNode = @TargetNodeId BREAK;

        UPDATE #Queue SET Visited = 1 WHERE NodeId = @CurrentNode;

        INSERT INTO #Queue (NodeId, Distance, PathStr, Visited)
        SELECT 
            e.TargetNode,
            @CurrentDist + e.Weight,
            @CurrentPath + '->' + CAST(e.TargetNode AS NVARCHAR),
            0
        FROM Edges e
        WHERE e.SourceNode = @CurrentNode
        AND NOT EXISTS (SELECT 1 FROM #Queue WHERE NodeId = e.TargetNode AND Visited = 1);
    END

    SELECT @CurrentNode AS TargetNode, @CurrentDist AS ShortestDistance, @CurrentPath AS Path;
    DROP TABLE #Queue;
END

