import heapq
from pyspark.sql import functions as F
from pyspark.sql.types import StructType, StructField, IntegerType, StringType

def usp_graph_shortest_path(spark, source_node_id: int, target_node_id: int):
    # Collect edges to driver for Dijkstra (graph algorithms require driver-side for small graphs)
    edges = spark.table("edges") \
        .select("source_node", "target_node", "weight") \
        .collect()

    graph = {}
    for row in edges:
        graph.setdefault(row["source_node"], []).append((row["target_node"], row["weight"]))

    # Dijkstra's algorithm
    heap = [(0, source_node_id, str(source_node_id))]
    visited = set()
    shortest = None

    while heap:
        dist, node, path = heapq.heappop(heap)

        if node in visited:
            continue
        visited.add(node)

        if node == target_node_id:
            shortest = (node, dist, path)
            break

        for neighbor, weight in graph.get(node, []):
            if neighbor not in visited:
                heapq.heappush(heap, (dist + weight, neighbor, path + "->" + str(neighbor)))

    if shortest is None:
        shortest = (target_node_id, -1, "No path found")

    schema = StructType([
        StructField("target_node", IntegerType()),
        StructField("shortest_distance", IntegerType()),
        StructField("path", StringType())
    ])

    return spark.createDataFrame([shortest], schema=schema)

