CREATE OR REPLACE TRIGGER trg_audit_employee_changes
AFTER INSERT OR UPDATE OR DELETE ON employees
FOR EACH ROW
DECLARE
    v_operation VARCHAR2(10);
    v_changed_by VARCHAR2(100);
BEGIN
    v_changed_by := SYS_CONTEXT('USERENV', 'SESSION_USER');

    IF INSERTING THEN
        v_operation := 'INSERT';
        INSERT INTO employee_audit_log
            (audit_id, employee_id, operation, new_salary,
             new_department, changed_by, changed_at)
        VALUES
            (audit_seq.NEXTVAL, :NEW.employee_id, v_operation,
             :NEW.salary, :NEW.department_id, v_changed_by, SYSDATE);
    ELSIF UPDATING THEN
        v_operation := 'UPDATE';
        INSERT INTO employee_audit_log
            (audit_id, employee_id, operation, old_salary, new_salary,
             old_department, new_department, changed_by, changed_at)
        VALUES
            (audit_seq.NEXTVAL, :NEW.employee_id, v_operation,
             :OLD.salary, :NEW.salary, :OLD.department_id,
             :NEW.department_id, v_changed_by, SYSDATE);
    ELSIF DELETING THEN
        v_operation := 'DELETE';
        INSERT INTO employee_audit_log
            (audit_id, employee_id, operation, old_salary,
             old_department, changed_by, changed_at)
        VALUES
            (audit_seq.NEXTVAL, :OLD.employee_id, v_operation,
             :OLD.salary, :OLD.department_id, v_changed_by, SYSDATE);
    END IF;
END trg_audit_employee_changes;

CREATE OR REPLACE FUNCTION get_customer_lifetime_value(
    p_customer_id IN NUMBER
) RETURN NUMBER IS
    v_total_orders   NUMBER := 0;
    v_total_revenue  NUMBER := 0;
    v_avg_order      NUMBER := 0;
    v_tenure_months  NUMBER := 0;
    v_clv            NUMBER := 0;
    v_first_order    DATE;
BEGIN
    SELECT COUNT(order_id),
           SUM(total_amount),
           AVG(total_amount),
           MIN(order_date)
    INTO v_total_orders, v_total_revenue, v_avg_order, v_first_order
    FROM orders
    WHERE customer_id = p_customer_id
      AND status = 'COMPLETED';

    IF v_first_order IS NOT NULL THEN
        v_tenure_months := MONTHS_BETWEEN(SYSDATE, v_first_order);
        IF v_tenure_months > 0 THEN
            v_clv := (v_total_revenue / v_tenure_months) * 12;
        END IF;
    END IF;

    RETURN ROUND(v_clv, 2);
EXCEPTION
    WHEN NO_DATA_FOUND THEN
        RETURN 0;
    WHEN OTHERS THEN
        RETURN -1;
END get_customer_lifetime_value;

CREATE OR REPLACE TRIGGER trg_prevent_salary_decrease
BEFORE UPDATE OF salary ON employees
FOR EACH ROW
WHEN (NEW.salary < OLD.salary)
DECLARE
    v_pct_decrease NUMBER;
BEGIN
    v_pct_decrease := ROUND((:OLD.salary - :NEW.salary) / :OLD.salary * 100, 2);

    IF v_pct_decrease > 20 THEN
        RAISE_APPLICATION_ERROR(
            -20001,
            'Salary decrease of ' || v_pct_decrease ||
            '% exceeds the maximum allowed 20% reduction for employee ' ||
            :OLD.employee_id
        );
    END IF;

    INSERT INTO salary_change_log
        (log_id, employee_id, old_salary, new_salary, pct_change,
         change_type, logged_at)
    VALUES
        (log_seq.NEXTVAL, :OLD.employee_id, :OLD.salary, :NEW.salary,
         -v_pct_decrease, 'DECREASE', SYSDATE);
END trg_prevent_salary_decrease;

CREATE OR REPLACE FUNCTION format_phone_number(
    p_raw_phone IN VARCHAR2
) RETURN VARCHAR2 IS
    v_digits    VARCHAR2(20);
    v_formatted VARCHAR2(20);
BEGIN
    v_digits := REGEXP_REPLACE(p_raw_phone, '[^0-9]', '');

    IF LENGTH(v_digits) = 10 THEN
        v_formatted := '(' || SUBSTR(v_digits, 1, 3) || ') ' ||
                       SUBSTR(v_digits, 4, 3) || '-' ||
                       SUBSTR(v_digits, 7, 4);
    ELSIF LENGTH(v_digits) = 11 AND SUBSTR(v_digits, 1, 1) = '1' THEN
        v_formatted := '+1 (' || SUBSTR(v_digits, 2, 3) || ') ' ||
                       SUBSTR(v_digits, 5, 3) || '-' ||
                       SUBSTR(v_digits, 8, 4);
    ELSE
        v_formatted := p_raw_phone;
    END IF;

    RETURN v_formatted;
EXCEPTION
    WHEN OTHERS THEN
        RETURN p_raw_phone;
END format_phone_number;

CREATE OR REPLACE TRIGGER trg_update_inventory
AFTER INSERT ON order_items
FOR EACH ROW
DECLARE
    v_current_qty    NUMBER;
    v_product_name   VARCHAR2(200);
BEGIN
    SELECT quantity_on_hand, product_name
    INTO v_current_qty, v_product_name
    FROM products
    WHERE product_id = :NEW.product_id
    FOR UPDATE;

    IF v_current_qty < :NEW.quantity THEN
        RAISE_APPLICATION_ERROR(
            -20002,
            'Insufficient stock for product: ' || v_product_name ||
            '. Available: ' || v_current_qty ||
            ', Requested: ' || :NEW.quantity
        );
    END IF;

    UPDATE products
    SET quantity_on_hand = quantity_on_hand - :NEW.quantity,
        last_updated     = SYSDATE
    WHERE product_id = :NEW.product_id;

    IF (v_current_qty - :NEW.quantity) < 10 THEN
        INSERT INTO reorder_alerts (alert_id, product_id, current_qty, alert_date)
        VALUES (alert_seq.NEXTVAL, :NEW.product_id,
                v_current_qty - :NEW.quantity, SYSDATE);
    END IF;
END trg_update_inventory;

CREATE OR REPLACE FUNCTION calculate_compound_interest(
    p_principal     IN NUMBER,
    p_annual_rate   IN NUMBER,
    p_years         IN NUMBER,
    p_compounds_per_year IN NUMBER DEFAULT 12
) RETURN NUMBER IS
    v_rate_per_period NUMBER;
    v_total_periods   NUMBER;
    v_final_amount    NUMBER;
BEGIN
    IF p_principal <= 0 OR p_annual_rate < 0 OR p_years <= 0 THEN
        RAISE_APPLICATION_ERROR(-20010, 'Invalid input parameters');
    END IF;

    v_rate_per_period := p_annual_rate / 100 / p_compounds_per_year;
    v_total_periods   := p_years * p_compounds_per_year;
    v_final_amount    := p_principal * POWER(1 + v_rate_per_period, v_total_periods);

    RETURN ROUND(v_final_amount, 2);
EXCEPTION
    WHEN OTHERS THEN
        RAISE_APPLICATION_ERROR(-20011, 'Error in compound interest calculation: ' || SQLERRM);
END calculate_compound_interest;

CREATE OR REPLACE TRIGGER trg_log_login_activity
AFTER INSERT ON user_sessions
FOR EACH ROW
DECLARE
    v_prev_login     DATE;
    v_login_count    NUMBER;
    v_days_since     NUMBER;
BEGIN
    SELECT MAX(login_date), COUNT(*)
    INTO v_prev_login, v_login_count
    FROM user_sessions
    WHERE user_id = :NEW.user_id
      AND session_id != :NEW.session_id;

    IF v_prev_login IS NOT NULL THEN
        v_days_since := TRUNC(SYSDATE) - TRUNC(v_prev_login);
    ELSE
        v_days_since := NULL;
    END IF;

    INSERT INTO user_activity_log (
        log_id, user_id, login_date, ip_address,
        prev_login_date, days_since_last_login,
        total_logins, is_returning_user
    ) VALUES (
        activity_seq.NEXTVAL,
        :NEW.user_id,
        :NEW.login_date,
        :NEW.ip_address,
        v_prev_login,
        v_days_since,
        v_login_count + 1,
        CASE WHEN v_login_count > 0 THEN 'Y' ELSE 'N' END
    );
END trg_log_login_activity;

CREATE OR REPLACE FUNCTION get_product_category_path(
    p_category_id IN NUMBER
) RETURN VARCHAR2 IS
    v_path       VARCHAR2(4000) := '';
    v_cat_name   VARCHAR2(200);
    v_parent_id  NUMBER;
    v_current_id NUMBER := p_category_id;
    v_depth      NUMBER := 0;
BEGIN
    LOOP
        SELECT category_name, parent_category_id
        INTO v_cat_name, v_parent_id
        FROM product_categories
        WHERE category_id = v_current_id;

        IF v_depth = 0 THEN
            v_path := v_cat_name;
        ELSE
            v_path := v_cat_name || ' > ' || v_path;
        END IF;

        EXIT WHEN v_parent_id IS NULL;
        v_current_id := v_parent_id;
        v_depth := v_depth + 1;

        IF v_depth > 10 THEN
            EXIT;
        END IF;
    END LOOP;

    RETURN v_path;
EXCEPTION
    WHEN NO_DATA_FOUND THEN
        RETURN NULL;
END get_product_category_path;

CREATE PROCEDURE ValidateAndGetCustomerStatus
    @CustomerID INT,
    @StatusCode NVARCHAR(20) OUTPUT,
    @CreditLimit DECIMAL(18,2) OUTPUT,
    @IsEligible BIT OUTPUT,
    @Message NVARCHAR(500) OUTPUT
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @TotalOrders INT;
    DECLARE @TotalSpend DECIMAL(18,2);
    DECLARE @DaysSinceLastOrder INT;

    SELECT
        @TotalOrders = COUNT(o.OrderID),
        @TotalSpend = SUM(o.TotalAmount),
        @DaysSinceLastOrder = DATEDIFF(DAY, MAX(o.OrderDate), GETDATE())
    FROM Orders o
    WHERE o.CustomerID = @CustomerID
      AND o.Status = 'Completed';

    IF @TotalOrders IS NULL
    BEGIN
        SET @StatusCode = 'NEW';
        SET @CreditLimit = 500.00;
        SET @IsEligible = 0;
        SET @Message = 'New customer with no order history';
        RETURN;
    END

    IF @TotalSpend >= 50000 AND @DaysSinceLastOrder <= 90
    BEGIN
        SET @StatusCode = 'PLATINUM';
        SET @CreditLimit = 25000.00;
        SET @IsEligible = 1;
        SET @Message = 'Platinum customer eligible for premium benefits';
    END
    ELSE IF @TotalSpend >= 10000 AND @DaysSinceLastOrder <= 180
    BEGIN
        SET @StatusCode = 'GOLD';
        SET @CreditLimit = 10000.00;
        SET @IsEligible = 1;
        SET @Message = 'Gold customer eligible for standard benefits';
    END
    ELSE IF @TotalSpend >= 1000
    BEGIN
        SET @StatusCode = 'SILVER';
        SET @CreditLimit = 2500.00;
        SET @IsEligible = 1;
        SET @Message = 'Silver customer with basic benefits';
    END
    ELSE
    BEGIN
        SET @StatusCode = 'BRONZE';
        SET @CreditLimit = 500.00;
        SET @IsEligible = 0;
        SET @Message = 'Bronze customer does not meet eligibility threshold';
    END
END

CREATE PROCEDURE ProcessOrderWithInventoryCheck
    @OrderID INT,
    @ProcessedQty INT OUTPUT,
    @BackorderedQty INT OUTPUT,
    @TotalValue DECIMAL(18,2) OUTPUT,
    @ProcessingStatus NVARCHAR(50) OUTPUT
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @RequestedQty INT;
    DECLARE @AvailableQty INT;
    DECLARE @UnitPrice DECIMAL(10,2);
    DECLARE @ProductID INT;

    SELECT
        @ProductID = oi.ProductID,
        @RequestedQty = oi.Quantity,
        @UnitPrice = oi.UnitPrice
    FROM OrderItems oi
    WHERE oi.OrderID = @OrderID;

    SELECT @AvailableQty = QuantityOnHand
    FROM Inventory
    WHERE ProductID = @ProductID;

    IF @AvailableQty IS NULL
    BEGIN
        SET @ProcessedQty = 0;
        SET @BackorderedQty = @RequestedQty;
        SET @TotalValue = 0;
        SET @ProcessingStatus = 'PRODUCT_NOT_FOUND';
        RETURN;
    END

    IF @AvailableQty >= @RequestedQty
    BEGIN
        SET @ProcessedQty = @RequestedQty;
        SET @BackorderedQty = 0;
        SET @TotalValue = @RequestedQty * @UnitPrice;
        SET @ProcessingStatus = 'FULLY_PROCESSED';

        UPDATE Inventory
        SET QuantityOnHand = QuantityOnHand - @RequestedQty
        WHERE ProductID = @ProductID;
    END
    ELSE IF @AvailableQty > 0
    BEGIN
        SET @ProcessedQty = @AvailableQty;
        SET @BackorderedQty = @RequestedQty - @AvailableQty;
        SET @TotalValue = @AvailableQty * @UnitPrice;
        SET @ProcessingStatus = 'PARTIALLY_PROCESSED';

        UPDATE Inventory
        SET QuantityOnHand = 0
        WHERE ProductID = @ProductID;
    END
    ELSE
    BEGIN
        SET @ProcessedQty = 0;
        SET @BackorderedQty = @RequestedQty;
        SET @TotalValue = 0;
        SET @ProcessingStatus = 'OUT_OF_STOCK';
    END
END

CREATE PROCEDURE CalculateShippingCost
    @OrderID INT,
    @ShippingMethod NVARCHAR(50),
    @DestinationZone INT,
    @ShippingCost DECIMAL(10,2) OUTPUT,
    @EstimatedDays INT OUTPUT,
    @DiscountApplied BIT OUTPUT,
    @FinalCost DECIMAL(10,2) OUTPUT
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @OrderWeight DECIMAL(10,2);
    DECLARE @OrderValue DECIMAL(18,2);
    DECLARE @BaseRate DECIMAL(10,2);
    DECLARE @ZoneMultiplier DECIMAL(5,2);

    SELECT
        @OrderWeight = SUM(p.WeightKg * oi.Quantity),
        @OrderValue = SUM(oi.UnitPrice * oi.Quantity)
    FROM OrderItems oi
    JOIN Products p ON oi.ProductID = p.ProductID
    WHERE oi.OrderID = @OrderID;

    IF @ShippingMethod = 'EXPRESS'
    BEGIN
        SET @BaseRate = 15.00;
        SET @EstimatedDays = 1;
    END
    ELSE IF @ShippingMethod = 'PRIORITY'
    BEGIN
        SET @BaseRate = 8.00;
        SET @EstimatedDays = 3;
    END
    ELSE
    BEGIN
        SET @BaseRate = 4.00;
        SET @EstimatedDays = 7;
    END

    SET @ZoneMultiplier = CASE @DestinationZone
        WHEN 1 THEN 1.0
        WHEN 2 THEN 1.3
        WHEN 3 THEN 1.6
        WHEN 4 THEN 2.0
        ELSE 2.5
    END;

    SET @ShippingCost = @BaseRate * @ZoneMultiplier * @OrderWeight;

    IF @OrderValue >= 100.00
    BEGIN
        SET @DiscountApplied = 1;
        SET @FinalCost = @ShippingCost * 0.80;
    END
    ELSE
    BEGIN
        SET @DiscountApplied = 0;
        SET @FinalCost = @ShippingCost;
    END
END

CREATE PROCEDURE GetEmployeePerformanceMetrics
    @EmployeeID INT,
    @StartDate DATE,
    @EndDate DATE,
    @TotalSales DECIMAL(18,2) OUTPUT,
    @SalesCount INT OUTPUT,
    @AvgDealSize DECIMAL(18,2) OUTPUT,
    @PerformanceTier NVARCHAR(20) OUTPUT,
    @BonusEligible BIT OUTPUT,
    @QuotaAttainmentPct DECIMAL(5,2) OUTPUT
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @QuotaTarget DECIMAL(18,2);

    SELECT @QuotaTarget = q.QuotaAmount
    FROM SalesQuotas q
    WHERE q.EmployeeID = @EmployeeID
      AND q.QuotaYear = YEAR(@StartDate);

    SELECT
        @TotalSales = ISNULL(SUM(s.SaleAmount), 0),
        @SalesCount = COUNT(s.SaleID)
    FROM Sales s
    WHERE s.EmployeeID = @EmployeeID
      AND s.SaleDate BETWEEN @StartDate AND @EndDate
      AND s.Status = 'Won';

    IF @SalesCount > 0
        SET @AvgDealSize = @TotalSales / @SalesCount;
    ELSE
        SET @AvgDealSize = 0;

    IF @QuotaTarget IS NULL OR @QuotaTarget = 0
        SET @QuotaAttainmentPct = 0;
    ELSE
        SET @QuotaAttainmentPct = ROUND((@TotalSales / @QuotaTarget) * 100, 2);

    IF @QuotaAttainmentPct >= 120
    BEGIN
        SET @PerformanceTier = 'ELITE';
        SET @BonusEligible = 1;
    END
    ELSE IF @QuotaAttainmentPct >= 100
    BEGIN
        SET @PerformanceTier = 'ACHIEVER';
        SET @BonusEligible = 1;
    END
    ELSE IF @QuotaAttainmentPct >= 80
    BEGIN
        SET @PerformanceTier = 'CONTRIBUTOR';
        SET @BonusEligible = 0;
    END
    ELSE
    BEGIN
        SET @PerformanceTier = 'NEEDS_IMPROVEMENT';
        SET @BonusEligible = 0;
    END
END

CREATE PROCEDURE CheckAndApplyPromoCode
    @PromoCode NVARCHAR(50),
    @CustomerID INT,
    @CartTotal DECIMAL(18,2),
    @DiscountAmount DECIMAL(18,2) OUTPUT,
    @FinalTotal DECIMAL(18,2) OUTPUT,
    @IsValid BIT OUTPUT,
    @ValidationMessage NVARCHAR(500) OUTPUT
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @MinOrderValue DECIMAL(18,2);
    DECLARE @MaxDiscountAmt DECIMAL(18,2);
    DECLARE @DiscountType NVARCHAR(20);
    DECLARE @DiscountValue DECIMAL(10,2);
    DECLARE @UsageLimit INT;
    DECLARE @CurrentUsage INT;
    DECLARE @ExpiryDate DATE;
    DECLARE @UsedByCustomer INT;

    SELECT
        @MinOrderValue = MinOrderValue,
        @MaxDiscountAmt = MaxDiscountAmount,
        @DiscountType = DiscountType,
        @DiscountValue = DiscountValue,
        @UsageLimit = UsageLimit,
        @ExpiryDate = ExpiryDate
    FROM PromoCodes
    WHERE PromoCode = @PromoCode AND IsActive = 1;

    IF @@ROWCOUNT = 0
    BEGIN
        SET @IsValid = 0;
        SET @DiscountAmount = 0;
        SET @FinalTotal = @CartTotal;
        SET @ValidationMessage = 'Promo code not found or inactive';
        RETURN;
    END

    IF @ExpiryDate < CAST(GETDATE() AS DATE)
    BEGIN
        SET @IsValid = 0;
        SET @DiscountAmount = 0;
        SET @FinalTotal = @CartTotal;
        SET @ValidationMessage = 'Promo code has expired';
        RETURN;
    END

    SELECT @CurrentUsage = COUNT(*) FROM PromoUsage WHERE PromoCode = @PromoCode;
    IF @CurrentUsage >= @UsageLimit
    BEGIN
        SET @IsValid = 0;
        SET @DiscountAmount = 0;
        SET @FinalTotal = @CartTotal;
        SET @ValidationMessage = 'Promo code usage limit reached';
        RETURN;
    END

    SELECT @UsedByCustomer = COUNT(*) FROM PromoUsage
    WHERE PromoCode = @PromoCode AND CustomerID = @CustomerID;
    IF @UsedByCustomer > 0
    BEGIN
        SET @IsValid = 0;
        SET @DiscountAmount = 0;
        SET @FinalTotal = @CartTotal;
        SET @ValidationMessage = 'Promo code already used by this customer';
        RETURN;
    END

    IF @CartTotal < @MinOrderValue
    BEGIN
        SET @IsValid = 0;
        SET @DiscountAmount = 0;
        SET @FinalTotal = @CartTotal;
        SET @ValidationMessage = 'Cart total does not meet minimum order value of ' + CAST(@MinOrderValue AS NVARCHAR);
        RETURN;
    END

    IF @DiscountType = 'PERCENTAGE'
        SET @DiscountAmount = ROUND(CASE WHEN (@CartTotal * @DiscountValue / 100) > @MaxDiscountAmt
                                         THEN @MaxDiscountAmt
                                         ELSE (@CartTotal * @DiscountValue / 100) END, 2);
    ELSE
        SET @DiscountAmount = CASE WHEN @DiscountValue > @MaxDiscountAmt
                                   THEN @MaxDiscountAmt ELSE @DiscountValue END;

    SET @IsValid = 1;
    SET @FinalTotal = @CartTotal - @DiscountAmount;
    SET @ValidationMessage = 'Promo code applied successfully';
END

CREATE PROCEDURE RecalculateAccountBalance
    @AccountID INT,
    @StartingBalance DECIMAL(18,2),
    @NewBalance DECIMAL(18,2) OUTPUT,
    @TotalCredits DECIMAL(18,2) OUTPUT,
    @TotalDebits DECIMAL(18,2) OUTPUT,
    @TransactionCount INT OUTPUT,
    @HasOverdraft BIT OUTPUT
AS
BEGIN
    SET NOCOUNT ON;

    SELECT
        @TotalCredits = ISNULL(SUM(CASE WHEN TransactionType = 'CREDIT' THEN Amount ELSE 0 END), 0),
        @TotalDebits = ISNULL(SUM(CASE WHEN TransactionType = 'DEBIT' THEN Amount ELSE 0 END), 0),
        @TransactionCount = COUNT(TransactionID)
    FROM Transactions
    WHERE AccountID = @AccountID
      AND Status = 'POSTED'
      AND TransactionDate >= DATEADD(MONTH, -1, GETDATE());

    SET @NewBalance = @StartingBalance + @TotalCredits - @TotalDebits;

    IF @NewBalance < 0
        SET @HasOverdraft = 1;
    ELSE
        SET @HasOverdraft = 0;

    UPDATE Accounts
    SET CurrentBalance = @NewBalance,
        LastRecalculated = GETDATE()
    WHERE AccountID = @AccountID;
END

CREATE PROCEDURE EvaluateLoanApplication
    @ApplicantID INT,
    @LoanAmount DECIMAL(18,2),
    @LoanTermMonths INT,
    @ApprovalStatus NVARCHAR(20) OUTPUT,
    @ApprovedAmount DECIMAL(18,2) OUTPUT,
    @InterestRate DECIMAL(5,2) OUTPUT,
    @MonthlyPayment DECIMAL(10,2) OUTPUT,
    @RejectionReason NVARCHAR(500) OUTPUT
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @CreditScore INT;
    DECLARE @AnnualIncome DECIMAL(18,2);
    DECLARE @ExistingDebt DECIMAL(18,2);
    DECLARE @DTIRatio DECIMAL(5,2);
    DECLARE @MaxLoanAmount DECIMAL(18,2);
    DECLARE @MonthlyIncome DECIMAL(18,2);

    SELECT @CreditScore = CreditScore, @AnnualIncome = AnnualIncome
    FROM Applicants
    WHERE ApplicantID = @ApplicantID;

    SELECT @ExistingDebt = ISNULL(SUM(MonthlyPayment), 0)
    FROM ExistingLoans
    WHERE ApplicantID = @ApplicantID AND Status = 'ACTIVE';

    SET @MonthlyIncome = @AnnualIncome / 12;
    SET @DTIRatio = ROUND((@ExistingDebt / NULLIF(@MonthlyIncome, 0)) * 100, 2);

    IF @CreditScore < 580
    BEGIN
        SET @ApprovalStatus = 'REJECTED';
        SET @ApprovedAmount = 0;
        SET @InterestRate = 0;
        SET @MonthlyPayment = 0;
        SET @RejectionReason = 'Credit score below minimum threshold of 580';
        RETURN;
    END

    IF @DTIRatio > 43
    BEGIN
        SET @ApprovalStatus = 'REJECTED';
        SET @ApprovedAmount = 0;
        SET @InterestRate = 0;
        SET @MonthlyPayment = 0;
        SET @RejectionReason = 'Debt-to-income ratio of ' + CAST(@DTIRatio AS NVARCHAR) + '% exceeds 43% limit';
        RETURN;
    END

    SET @MaxLoanAmount = @AnnualIncome * 0.40;
    IF @LoanAmount > @MaxLoanAmount
        SET @ApprovedAmount = @MaxLoanAmount;
    ELSE
        SET @ApprovedAmount = @LoanAmount;

    IF @CreditScore >= 750
        SET @InterestRate = 4.5;
    ELSE IF @CreditScore >= 700
        SET @InterestRate = 6.5;
    ELSE IF @CreditScore >= 650
        SET @InterestRate = 9.0;
    ELSE
        SET @InterestRate = 12.5;

    DECLARE @MonthlyRate DECIMAL(10,8);
    SET @MonthlyRate = @InterestRate / 100 / 12;
    SET @MonthlyPayment = ROUND(
        @ApprovedAmount * @MonthlyRate * POWER(1 + @MonthlyRate, @LoanTermMonths)
        / (POWER(1 + @MonthlyRate, @LoanTermMonths) - 1), 2);

    SET @ApprovalStatus = 'APPROVED';
    SET @RejectionReason = NULL;
END

CREATE PROCEDURE GenerateReorderSuggestions
    @WarehouseID INT,
    @TotalReorderCost DECIMAL(18,2) OUTPUT,
    @ProductsToReorder INT OUTPUT,
    @UrgentReorderCount INT OUTPUT,
    @BudgetSufficient BIT OUTPUT
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @AvailableBudget DECIMAL(18,2);

    SELECT @AvailableBudget = ProcurementBudget
    FROM Warehouses
    WHERE WarehouseID = @WarehouseID;

    CREATE TABLE #ReorderList (
        ProductID INT,
        ProductName NVARCHAR(200),
        CurrentQty INT,
        ReorderLevel INT,
        ReorderQty INT,
        UnitCost DECIMAL(10,2),
        ReorderCost DECIMAL(18,2),
        IsUrgent BIT
    );

    INSERT INTO #ReorderList
    SELECT
        p.ProductID,
        p.ProductName,
        i.QuantityOnHand,
        i.ReorderLevel,
        i.ReorderQuantity,
        p.UnitCost,
        i.ReorderQuantity * p.UnitCost AS ReorderCost,
        CASE WHEN i.QuantityOnHand = 0 THEN 1 ELSE 0 END AS IsUrgent
    FROM Inventory i
    JOIN Products p ON i.ProductID = p.ProductID
    WHERE i.WarehouseID = @WarehouseID
      AND i.QuantityOnHand < i.ReorderLevel;

    SELECT
        @TotalReorderCost = ISNULL(SUM(ReorderCost), 0),
        @ProductsToReorder = COUNT(ProductID),
        @UrgentReorderCount = SUM(CASE WHEN IsUrgent = 1 THEN 1 ELSE 0 END)
    FROM #ReorderList;

    IF @TotalReorderCost <= @AvailableBudget
        SET @BudgetSufficient = 1;
    ELSE
        SET @BudgetSufficient = 0;

    SELECT * FROM #ReorderList ORDER BY IsUrgent DESC, ReorderCost DESC;

    DROP TABLE #ReorderList;
END

CREATE PROCEDURE TransferFundsBetweenAccounts
    @FromAccountID INT,
    @ToAccountID INT,
    @TransferAmount DECIMAL(18,2),
    @TransactionRefID NVARCHAR(50) OUTPUT,
    @TransferStatus NVARCHAR(30) OUTPUT,
    @FromNewBalance DECIMAL(18,2) OUTPUT,
    @ToNewBalance DECIMAL(18,2) OUTPUT,
    @StatusMessage NVARCHAR(500) OUTPUT
AS
BEGIN
    SET NOCOUNT ON;
    BEGIN TRANSACTION;

    DECLARE @FromBalance DECIMAL(18,2);
    DECLARE @ToBalance DECIMAL(18,2);
    DECLARE @FromStatus NVARCHAR(20);
    DECLARE @ToStatus NVARCHAR(20);

    SELECT @FromBalance = Balance, @FromStatus = AccountStatus
    FROM Accounts WHERE AccountID = @FromAccountID;

    SELECT @ToBalance = Balance, @ToStatus = AccountStatus
    FROM Accounts WHERE AccountID = @ToAccountID;

    IF @FromBalance IS NULL OR @ToBalance IS NULL
    BEGIN
        SET @TransferStatus = 'FAILED';
        SET @StatusMessage = 'One or both accounts not found';
        ROLLBACK TRANSACTION;
        RETURN;
    END

    IF @FromStatus != 'ACTIVE' OR @ToStatus != 'ACTIVE'
    BEGIN
        SET @TransferStatus = 'FAILED';
        SET @StatusMessage = 'One or both accounts are not active';
        ROLLBACK TRANSACTION;
        RETURN;
    END

    IF @FromBalance < @TransferAmount
    BEGIN
        SET @TransferStatus = 'FAILED';
        SET @StatusMessage = 'Insufficient funds in source account';
        ROLLBACK TRANSACTION;
        RETURN;
    END

    UPDATE Accounts SET Balance = Balance - @TransferAmount WHERE AccountID = @FromAccountID;
    UPDATE Accounts SET Balance = Balance + @TransferAmount WHERE AccountID = @ToAccountID;

    SET @TransactionRefID = 'TXN' + CAST(NEWID() AS NVARCHAR(36));
    SET @FromNewBalance = @FromBalance - @TransferAmount;
    SET @ToNewBalance = @ToBalance + @TransferAmount;
    SET @TransferStatus = 'SUCCESS';
    SET @StatusMessage = 'Transfer completed successfully';

    INSERT INTO TransactionLog (RefID, FromAccountID, ToAccountID, Amount, TransferDate, Status)
    VALUES (@TransactionRefID, @FromAccountID, @ToAccountID, @TransferAmount, GETDATE(), 'SUCCESS');

    COMMIT TRANSACTION;
END

CREATE PROCEDURE AnalyzeProductSalesVelocity
    @ProductID INT,
    @AnalysisPeriodDays INT = 90,
    @AvgDailySales DECIMAL(10,4) OUTPUT,
    @DaysOfStockRemaining INT OUTPUT,
    @VelocityCategory NVARCHAR(30) OUTPUT,
    @RecommendedAction NVARCHAR(200) OUTPUT,
    @ProjectedStockoutDate DATE OUTPUT
AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @TotalUnitsSold INT;
    DECLARE @CurrentStock INT;
    DECLARE @CutoffDate DATE;
    DECLARE @ActualDaysWithSales INT;

    SET @CutoffDate = DATEADD(DAY, -@AnalysisPeriodDays, GETDATE());

    SELECT @TotalUnitsSold = ISNULL(SUM(od.Quantity), 0),
           @ActualDaysWithSales = COUNT(DISTINCT CAST(o.OrderDate AS DATE))
    FROM OrderDetails od
    JOIN Orders o ON od.OrderID = o.OrderID
    WHERE od.ProductID = @ProductID
      AND o.OrderDate >= @CutoffDate
      AND o.Status = 'Completed';

    SELECT @CurrentStock = QuantityOnHand
    FROM Inventory
    WHERE ProductID = @ProductID;

    IF @ActualDaysWithSales = 0 OR @TotalUnitsSold = 0
    BEGIN
        SET @AvgDailySales = 0;
        SET @DaysOfStockRemaining = -1;
        SET @VelocityCategory = 'DEAD_STOCK';
        SET @RecommendedAction = 'Consider clearance or discontinuation';
        SET @ProjectedStockoutDate = NULL;
        RETURN;
    END

    SET @AvgDailySales = CAST(@TotalUnitsSold AS DECIMAL(10,4)) / @AnalysisPeriodDays;

    IF @AvgDailySales > 0
        SET @DaysOfStockRemaining = CAST(FLOOR(@CurrentStock / @AvgDailySales) AS INT);
    ELSE
        SET @DaysOfStockRemaining = -1;

    IF @AvgDailySales >= 50
    BEGIN
        SET @VelocityCategory = 'FAST_MOVER';
        SET @RecommendedAction = 'Increase reorder frequency and safety stock';
    END
    ELSE IF @AvgDailySales >= 10
    BEGIN
        SET @VelocityCategory = 'MEDIUM_MOVER';
        SET @RecommendedAction = 'Maintain current reorder policy';
    END
    ELSE IF @AvgDailySales >= 1
    BEGIN
        SET @VelocityCategory = 'SLOW_MOVER';
        SET @RecommendedAction = 'Review reorder quantities and reduce safety stock';
    END
    ELSE
    BEGIN
        SET @VelocityCategory = 'VERY_SLOW_MOVER';
        SET @RecommendedAction = 'Evaluate product viability and consider promotions';
    END

    IF @DaysOfStockRemaining >= 0
        SET @ProjectedStockoutDate = CAST(DATEADD(DAY, @DaysOfStockRemaining, GETDATE()) AS DATE);
    ELSE
        SET @ProjectedStockoutDate = NULL;
END

DECLARE
  CURSOR c_overdue IS
    SELECT loan_id, borrower_id, outstanding_balance, due_date
    FROM loan_accounts
    WHERE due_date < SYSDATE AND payment_status = 'pending'
    ORDER BY outstanding_balance DESC;
  v_penalty NUMBER;
BEGIN
  FOR rec IN c_overdue LOOP
    v_penalty := rec.outstanding_balance * 0.02;
    UPDATE loan_accounts
    SET penalty_amount = v_penalty,
        payment_status = 'overdue',
        updated_at = SYSDATE
    WHERE loan_id = rec.loan_id;
    INSERT INTO penalty_audit_log (loan_id, borrower_id, penalty_amount, applied_at)
    VALUES (rec.loan_id, rec.borrower_id, v_penalty, SYSDATE);
  END LOOP;
  COMMIT;
END;

DECLARE
  TYPE t_sku_tab IS TABLE OF VARCHAR2(50);
  TYPE t_qty_tab IS TABLE OF NUMBER;
  v_skus  t_sku_tab;
  v_qtys  t_qty_tab;
  v_warehouse_id NUMBER := 101;
BEGIN
  SELECT sku, reorder_qty
  BULK COLLECT INTO v_skus, v_qtys
  FROM warehouse_inventory
  WHERE warehouse_id = v_warehouse_id
  AND current_stock < reorder_threshold;

  FORALL i IN 1..v_skus.COUNT
    INSERT INTO reorder_requests (warehouse_id, sku, requested_qty, request_date)
    VALUES (v_warehouse_id, v_skus(i), v_qtys(i), SYSDATE);

  COMMIT;
EXCEPTION
  WHEN OTHERS THEN
    ROLLBACK;
    INSERT INTO error_log (proc_name, error_msg, logged_at)
    VALUES ('reorder_proc', SQLERRM, SYSDATE);
    COMMIT;
END;

CREATE OR REPLACE PROCEDURE reconcile_meter_readings(
  p_billing_period VARCHAR2
) AS
  v_count    NUMBER := 0;
  v_mismatch NUMBER := 0;
  CURSOR c_meters IS
    SELECT m.meter_id, m.customer_id, m.last_reading,
           b.billed_units
    FROM smart_meters m
    JOIN billing_records b ON m.meter_id = b.meter_id
    WHERE b.billing_period = p_billing_period
    AND m.last_reading <> b.billed_units;
BEGIN
  FOR rec IN c_meters LOOP
    v_count := v_count + 1;
    v_mismatch := v_mismatch + ABS(rec.last_reading - rec.billed_units);
    UPDATE billing_records
    SET billed_units = rec.last_reading,
        reconciled = 'Y',
        reconciled_at = SYSDATE
    WHERE meter_id = rec.meter_id
    AND billing_period = p_billing_period;
  END LOOP;
  INSERT INTO reconciliation_summary
    (billing_period, meters_reconciled, total_unit_variance, run_at)
  VALUES (p_billing_period, v_count, v_mismatch, SYSDATE);
  COMMIT;
END;

DECLARE
  v_portfolio_id  NUMBER := 2045;
  v_total_nav     NUMBER := 0;
  v_asset_count   NUMBER := 0;
  CURSOR c_assets IS
    SELECT asset_id, asset_type, market_value, weight
    FROM portfolio_holdings
    WHERE portfolio_id = v_portfolio_id
    AND active_flag = 'Y';
BEGIN
  FOR rec IN c_assets LOOP
    v_total_nav   := v_total_nav + rec.market_value;
    v_asset_count := v_asset_count + 1;
    UPDATE portfolio_holdings
    SET last_valued_at = SYSDATE
    WHERE asset_id = rec.asset_id
    AND portfolio_id = v_portfolio_id;
  END LOOP;
  UPDATE portfolio_summary
  SET total_nav = v_total_nav,
      asset_count = v_asset_count,
      last_refreshed = SYSDATE
  WHERE portfolio_id = v_portfolio_id;
  COMMIT;
EXCEPTION
  WHEN NO_DATA_FOUND THEN
    DBMS_OUTPUT.PUT_LINE('No active holdings for portfolio: ' || v_portfolio_id);
  WHEN OTHERS THEN
    ROLLBACK;
    RAISE;
END;

CREATE OR REPLACE PROCEDURE expire_promotions AS
  TYPE t_promo IS TABLE OF promotions%ROWTYPE;
  v_promos t_promo;
  v_expired_count NUMBER := 0;
BEGIN
  SELECT * BULK COLLECT INTO v_promos
  FROM promotions
  WHERE end_date < SYSDATE
  AND promo_status <> 'expired';

  FORALL i IN 1..v_promos.COUNT
    UPDATE promotions
    SET promo_status = 'expired',
        expired_at   = SYSDATE
    WHERE promo_id = v_promos(i).promo_id;

  v_expired_count := SQL%ROWCOUNT;

  INSERT INTO promo_lifecycle_log
    (event_type, affected_count, event_time)
  VALUES ('bulk_expire', v_expired_count, SYSDATE);

  COMMIT;
END;

DECLARE
  CURSOR c_segments IS
    SELECT segment_id, segment_name, min_spend, max_spend
    FROM loyalty_segments
    ORDER BY min_spend;
  v_updated NUMBER := 0;
BEGIN
  FOR seg IN c_segments LOOP
    UPDATE loyalty_members
    SET segment_id = seg.segment_id,
        segment_updated_at = SYSDATE
    WHERE annual_spend BETWEEN seg.min_spend AND seg.max_spend
    AND (segment_id <> seg.segment_id OR segment_id IS NULL);
    v_updated := v_updated + SQL%ROWCOUNT;
  END LOOP;
  UPDATE loyalty_members
  SET segment_id = NULL,
      segment_updated_at = SYSDATE
  WHERE annual_spend IS NULL;
  DBMS_OUTPUT.PUT_LINE('Total members re-segmented: ' || v_updated);
  COMMIT;
END;

CREATE OR REPLACE PROCEDURE generate_invoice_snapshots(
  p_snapshot_date DATE
) AS
  v_batch_id  NUMBER;
  CURSOR c_invoices IS
    SELECT i.invoice_id, i.client_id, i.amount_due,
           i.currency, NVL(p.payment_amount, 0) AS paid
    FROM invoices i
    LEFT JOIN invoice_payments p ON i.invoice_id = p.invoice_id
    WHERE i.invoice_date <= p_snapshot_date
    AND i.invoice_status IN ('open', 'partial');
BEGIN
  SELECT NVL(MAX(batch_id), 0) + 1 INTO v_batch_id
  FROM invoice_snapshot_batches;

  INSERT INTO invoice_snapshot_batches (batch_id, snapshot_date, created_at)
  VALUES (v_batch_id, p_snapshot_date, SYSDATE);

  FOR rec IN c_invoices LOOP
    INSERT INTO invoice_snapshots
      (batch_id, invoice_id, client_id, amount_due, amount_paid,
       outstanding, currency, snapped_at)
    VALUES
      (v_batch_id, rec.invoice_id, rec.client_id, rec.amount_due,
       rec.paid, rec.amount_due - rec.paid, rec.currency, SYSDATE);
  END LOOP;
  COMMIT;
END;

DECLARE
  TYPE t_ids  IS TABLE OF NUMBER INDEX BY PLS_INTEGER;
  TYPE t_vals IS TABLE OF NUMBER INDEX BY PLS_INTEGER;
  v_site_ids  t_ids;
  v_emissions t_vals;
  v_threshold NUMBER := 500;
  v_alert_count NUMBER := 0;
BEGIN
  SELECT site_id, AVG(emission_value)
  BULK COLLECT INTO v_site_ids, v_emissions
  FROM emission_readings
  WHERE reading_date >= TRUNC(SYSDATE) - 7
  GROUP BY site_id
  HAVING AVG(emission_value) > v_threshold;

  FORALL i IN 1..v_site_ids.COUNT
    INSERT INTO emission_alerts
      (site_id, avg_emission, alert_level, raised_at)
    VALUES
      (v_site_ids(i), v_emissions(i),
       CASE WHEN v_emissions(i) > 1000 THEN 'critical' ELSE 'warning' END,
       SYSDATE);

  v_alert_count := v_site_ids.COUNT;
  DBMS_OUTPUT.PUT_LINE('Alerts raised: ' || v_alert_count);
  COMMIT;
END;

CREATE OR REPLACE PROCEDURE rebalance_ad_budgets(
  p_campaign_group_id NUMBER
) AS
  v_total_budget   NUMBER;
  v_total_spend    NUMBER;
  v_remaining      NUMBER;
  v_ad_count       NUMBER;
  v_allocation     NUMBER;
  CURSOR c_ads IS
    SELECT ad_id, current_budget, current_spend
    FROM ad_campaigns
    WHERE campaign_group_id = p_campaign_group_id
    AND ad_status = 'active'
    FOR UPDATE;
BEGIN
  SELECT SUM(current_budget), SUM(current_spend), COUNT(*)
  INTO v_total_budget, v_total_spend, v_ad_count
  FROM ad_campaigns
  WHERE campaign_group_id = p_campaign_group_id
  AND ad_status = 'active';

  v_remaining  := v_total_budget - v_total_spend;
  v_allocation := ROUND(v_remaining / NULLIF(v_ad_count, 0), 2);

  FOR rec IN c_ads LOOP
    UPDATE ad_campaigns
    SET current_budget   = rec.current_spend + v_allocation,
        rebalanced_at    = SYSDATE
    WHERE CURRENT OF c_ads;
  END LOOP;
  COMMIT;
END;

DECLARE
  v_run_id      NUMBER;
  v_total_in    NUMBER := 0;
  v_total_out   NUMBER := 0;
  v_net         NUMBER;
  CURSOR c_flows IS
    SELECT f.account_id, f.flow_type, SUM(f.amount) AS flow_total
    FROM cash_flows f
    WHERE f.value_date = TRUNC(SYSDATE)
    GROUP BY f.account_id, f.flow_type;
BEGIN
  SELECT NVL(MAX(run_id), 0) + 1 INTO v_run_id FROM eod_cash_run_log;

  FOR rec IN c_flows LOOP
    IF rec.flow_type = 'inflow' THEN
      v_total_in := v_total_in + rec.flow_total;
    ELSIF rec.flow_type = 'outflow' THEN
      v_total_out := v_total_out + rec.flow_total;
    END IF;
    UPDATE account_balances
    SET balance = balance + CASE rec.flow_type
                              WHEN 'inflow'  THEN  rec.flow_total
                              WHEN 'outflow' THEN -rec.flow_total
                              ELSE 0
                            END,
        last_updated = SYSDATE
    WHERE account_id = rec.account_id;
  END LOOP;

  v_net := v_total_in - v_total_out;

  INSERT INTO eod_cash_run_log
    (run_id, run_date, total_inflow, total_outflow, net_position, logged_at)
  VALUES (v_run_id, TRUNC(SYSDATE), v_total_in, v_total_out, v_net, SYSDATE);
  COMMIT;
END;

BEGIN
  UPDATE flight_schedules
  SET status = 'cancelled',
      cancelled_at = SYSDATE,
      cancellation_reason = 'weather'
  WHERE departure_date = TRUNC(SYSDATE + 1)
  AND origin_airport = 'ORD'
  AND status = 'scheduled';
  COMMIT;
END;

DECLARE
  v_total_revenue NUMBER := 0;
  v_avg_ticket    NUMBER := 0;
  v_event_id      NUMBER := 3812;
BEGIN
  SELECT SUM(ticket_price), AVG(ticket_price)
  INTO v_total_revenue, v_avg_ticket
  FROM event_ticket_sales
  WHERE event_id = v_event_id
  AND sale_status = 'completed';

  UPDATE event_summary
  SET total_revenue  = v_total_revenue,
      avg_ticket_price = v_avg_ticket,
      last_updated   = SYSDATE
  WHERE event_id = v_event_id;
  COMMIT;
END;

DECLARE
  v_min_score  NUMBER := 75;
  v_cohort_id  NUMBER := 209;
BEGIN
  DELETE FROM training_enrollments
  WHERE cohort_id  = v_cohort_id
  AND final_score < v_min_score
  AND enrollment_status = 'failed';

  UPDATE training_cohorts
  SET completion_rate = (
    SELECT ROUND(COUNT(*) * 100.0 / NULLIF(total_seats, 0), 2)
    FROM training_enrollments
    WHERE cohort_id = v_cohort_id
    AND enrollment_status = 'passed'
  ),
  updated_at = SYSDATE
  WHERE cohort_id = v_cohort_id;
  COMMIT;
END;

DECLARE
  v_campaign_id NUMBER := 7731;
  v_total_sent  NUMBER;
  v_open_rate   NUMBER;
BEGIN
  SELECT COUNT(*),
         ROUND(SUM(CASE WHEN opened = 'Y' THEN 1 ELSE 0 END) * 100.0 / NULLIF(COUNT(*), 0), 2)
  INTO v_total_sent, v_open_rate
  FROM email_sends
  WHERE campaign_id = v_campaign_id;

  IF v_open_rate < 10 THEN
    UPDATE email_campaigns
    SET campaign_flag = 'low_engagement',
        flagged_at    = SYSDATE
    WHERE campaign_id = v_campaign_id;
  ELSIF v_open_rate >= 30 THEN
    UPDATE email_campaigns
    SET campaign_flag = 'high_engagement',
        flagged_at    = SYSDATE
    WHERE campaign_id = v_campaign_id;
  ELSE
    UPDATE email_campaigns
    SET campaign_flag = 'normal',
        flagged_at    = SYSDATE
    WHERE campaign_id = v_campaign_id;
  END IF;
  COMMIT;
END;

CREATE OR REPLACE PROCEDURE archive_completed_surveys(
  p_cutoff_date DATE
) AS
BEGIN
  INSERT INTO survey_archive
    (survey_id, respondent_id, submitted_at, score, archived_at)
  SELECT survey_id, respondent_id, submitted_at, score, SYSDATE
  FROM survey_responses
  WHERE submitted_at < p_cutoff_date
  AND response_status = 'completed';

  DELETE FROM survey_responses
  WHERE submitted_at  < p_cutoff_date
  AND response_status = 'completed';

  COMMIT;
END;

DECLARE
  v_node_id     NUMBER := 55;
  v_threshold   NUMBER := 90;
  v_avg_cpu     NUMBER;
  v_avg_mem     NUMBER;
BEGIN
  SELECT AVG(cpu_usage_pct), AVG(memory_usage_pct)
  INTO v_avg_cpu, v_avg_mem
  FROM server_metrics
  WHERE node_id    = v_node_id
  AND metric_time >= SYSDATE - (1/24);

  IF v_avg_cpu > v_threshold OR v_avg_mem > v_threshold THEN
    INSERT INTO server_alerts
      (node_id, alert_type, avg_cpu, avg_mem, raised_at)
    VALUES
      (v_node_id,
       CASE WHEN v_avg_cpu > v_threshold AND v_avg_mem > v_threshold THEN 'both'
            WHEN v_avg_cpu > v_threshold THEN 'cpu'
            ELSE 'memory' END,
       v_avg_cpu, v_avg_mem, SYSDATE);
  END IF;
  COMMIT;
END;

DECLARE
  v_region      VARCHAR2(50) := 'APAC';
  v_target_rev  NUMBER       := 1000000;
  v_actual_rev  NUMBER;
  v_attainment  NUMBER;
BEGIN
  SELECT SUM(deal_value)
  INTO v_actual_rev
  FROM sales_deals
  WHERE region        = v_region
  AND close_date     BETWEEN TRUNC(SYSDATE, 'Q') AND LAST_DAY(ADD_MONTHS(TRUNC(SYSDATE, 'Q'), 2))
  AND deal_status    = 'won';

  v_attainment := ROUND((NVL(v_actual_rev, 0) / v_target_rev) * 100, 2);

  INSERT INTO quota_attainment_log
    (region, target_revenue, actual_revenue, attainment_pct, logged_at)
  VALUES
    (v_region, v_target_rev, NVL(v_actual_rev, 0), v_attainment, SYSDATE);
  COMMIT;
END;

CREATE OR REPLACE PROCEDURE rebalance_fund_portfolios(
  p_fund_family_id NUMBER,
  p_rebalance_date  DATE
) AS
  v_total_aum       NUMBER := 0;
  v_drift_threshold NUMBER := 0.05;
  CURSOR c_funds IS
    SELECT fund_id, fund_name, target_allocation
    FROM mutual_funds
    WHERE fund_family_id = p_fund_family_id AND active = 'Y';
  CURSOR c_holdings(p_fund_id NUMBER) IS
    SELECT h.asset_id, h.asset_class, h.current_value,
           h.current_value / NULLIF(f.nav, 0) AS weight
    FROM fund_holdings h
    JOIN fund_nav f ON f.fund_id = h.fund_id
    WHERE h.fund_id = p_fund_id
    AND f.nav_date = p_rebalance_date;
  v_drift NUMBER;
  v_batch_id NUMBER;
BEGIN
  SELECT NVL(MAX(batch_id), 0) + 1 INTO v_batch_id FROM rebalance_batches;
  INSERT INTO rebalance_batches (batch_id, fund_family_id, run_date, status)
  VALUES (v_batch_id, p_fund_family_id, p_rebalance_date, 'running');

  FOR fund_rec IN c_funds LOOP
    FOR hold_rec IN c_holdings(fund_rec.fund_id) LOOP
      v_drift := ABS(hold_rec.weight - fund_rec.target_allocation);
      IF v_drift > v_drift_threshold THEN
        INSERT INTO rebalance_orders
          (batch_id, fund_id, asset_id, asset_class, current_weight,
           target_weight, drift, order_type, created_at)
        VALUES
          (v_batch_id, fund_rec.fund_id, hold_rec.asset_id, hold_rec.asset_class,
           hold_rec.weight, fund_rec.target_allocation, v_drift,
           CASE WHEN hold_rec.weight > fund_rec.target_allocation THEN 'sell' ELSE 'buy' END,
           SYSDATE);
      END IF;
    END LOOP;
  END LOOP;

  UPDATE rebalance_batches SET status = 'completed', completed_at = SYSDATE
  WHERE batch_id = v_batch_id;
  COMMIT;
EXCEPTION
  WHEN OTHERS THEN
    UPDATE rebalance_batches SET status = 'failed', error_msg = SQLERRM
    WHERE batch_id = v_batch_id;
    COMMIT;
    RAISE;
END;

CREATE OR REPLACE PROCEDURE run_credit_scoring_batch(
  p_bureau_snapshot_date DATE
) AS
  TYPE t_app_ids   IS TABLE OF NUMBER;
  TYPE t_scores    IS TABLE OF NUMBER;
  TYPE t_grades    IS TABLE OF VARCHAR2(5);
  v_app_ids   t_app_ids;
  v_scores    t_scores;
  v_grades    t_grades;
  v_failed    NUMBER := 0;
  v_succeeded NUMBER := 0;
  CURSOR c_apps IS
    SELECT a.application_id,
           (b.payment_history_score * 0.35
          + b.utilization_score     * 0.30
          + b.credit_age_score      * 0.15
          + b.mix_score             * 0.10
          + b.inquiry_score         * 0.10) AS composite_score
    FROM loan_applications a
    JOIN credit_bureau_data b ON a.applicant_id = b.applicant_id
    WHERE b.snapshot_date   = p_bureau_snapshot_date
    AND a.decision_status   = 'pending';
BEGIN
  SELECT application_id,
         (b.payment_history_score * 0.35 + b.utilization_score * 0.30
        + b.credit_age_score * 0.15 + b.mix_score * 0.10 + b.inquiry_score * 0.10),
         CASE
           WHEN (b.payment_history_score*0.35+b.utilization_score*0.30
                +b.credit_age_score*0.15+b.mix_score*0.10+b.inquiry_score*0.10) >= 750 THEN 'A'
           WHEN (b.payment_history_score*0.35+b.utilization_score*0.30
                +b.credit_age_score*0.15+b.mix_score*0.10+b.inquiry_score*0.10) >= 650 THEN 'B'
           WHEN (b.payment_history_score*0.35+b.utilization_score*0.30
                +b.credit_age_score*0.15+b.mix_score*0.10+b.inquiry_score*0.10) >= 550 THEN 'C'
           ELSE 'D'
         END
  BULK COLLECT INTO v_app_ids, v_scores, v_grades
  FROM loan_applications a
  JOIN credit_bureau_data b ON a.applicant_id = b.applicant_id
  WHERE b.snapshot_date = p_bureau_snapshot_date
  AND a.decision_status = 'pending';

  FORALL i IN 1..v_app_ids.COUNT SAVE EXCEPTIONS
    UPDATE loan_applications
    SET credit_score   = v_scores(i),
        credit_grade   = v_grades(i),
        scored_at      = SYSDATE,
        decision_status = CASE WHEN v_grades(i) IN ('A','B') THEN 'approved'
                               WHEN v_grades(i) = 'C' THEN 'review'
                               ELSE 'declined' END
    WHERE application_id = v_app_ids(i);

  v_succeeded := SQL%ROWCOUNT;
  INSERT INTO credit_score_batch_log
    (snapshot_date, total_scored, failed_count, run_at)
  VALUES (p_bureau_snapshot_date, v_succeeded, 0, SYSDATE);
  COMMIT;
EXCEPTION
  WHEN OTHERS THEN
    v_failed := SQL%BULK_EXCEPTIONS.COUNT;
    INSERT INTO credit_score_batch_log
      (snapshot_date, total_scored, failed_count, run_at)
    VALUES (p_bureau_snapshot_date, v_succeeded, v_failed, SYSDATE);
    COMMIT;
END;

CREATE OR REPLACE PROCEDURE process_insurance_claims_batch(
  p_batch_date DATE
) AS
  v_sql        VARCHAR2(4000);
  v_table_name VARCHAR2(100);
  v_cnt        NUMBER;
  CURSOR c_claim_types IS
    SELECT DISTINCT claim_type, LOWER(REPLACE(claim_type,' ','_')) AS tbl_suffix
    FROM insurance_claims
    WHERE submission_date = p_batch_date AND processing_status = 'new';
BEGIN
  FOR ctype IN c_claim_types LOOP
    v_table_name := 'claims_staging_' || ctype.tbl_suffix;
    v_sql := 'CREATE TABLE IF NOT EXISTS ' || v_table_name ||
             ' AS SELECT c.*, p.coverage_limit, p.deductible ' ||
             ' FROM insurance_claims c ' ||
             ' JOIN policy_coverage p ON c.policy_id = p.policy_id ' ||
             ' WHERE c.claim_type = ''' || ctype.claim_type || '''' ||
             ' AND c.submission_date = DATE ''' || TO_CHAR(p_batch_date,'YYYY-MM-DD') || '''';
    EXECUTE IMMEDIATE v_sql;

    EXECUTE IMMEDIATE 'SELECT COUNT(*) FROM ' || v_table_name INTO v_cnt;

    INSERT INTO claims_batch_manifest
      (batch_date, claim_type, staging_table, record_count, created_at)
    VALUES (p_batch_date, ctype.claim_type, v_table_name, v_cnt, SYSDATE);
  END LOOP;
  COMMIT;
END;

CREATE OR REPLACE PROCEDURE settle_interbank_positions(
  p_settlement_date DATE
) AS
  v_bank_id         NUMBER;
  v_net_position    NUMBER;
  v_settlement_id   NUMBER;
  TYPE t_bank_rec IS RECORD (
    bank_id         NUMBER,
    gross_send      NUMBER,
    gross_receive   NUMBER,
    net_position    NUMBER
  );
  TYPE t_bank_tab IS TABLE OF t_bank_rec;
  v_banks t_bank_tab;
BEGIN
  SELECT b.bank_id,
         SUM(CASE WHEN t.direction='send' THEN t.amount ELSE 0 END),
         SUM(CASE WHEN t.direction='receive' THEN t.amount ELSE 0 END),
         SUM(CASE WHEN t.direction='send' THEN -t.amount ELSE t.amount END)
  BULK COLLECT INTO v_banks
  FROM interbank_transactions t
  JOIN registered_banks b ON t.bank_id = b.bank_id
  WHERE t.settlement_date = p_settlement_date
  AND t.settled = 'N'
  GROUP BY b.bank_id;

  SELECT NVL(MAX(settlement_id),0)+1 INTO v_settlement_id FROM settlement_runs;
  INSERT INTO settlement_runs (settlement_id, settlement_date, bank_count, initiated_at)
  VALUES (v_settlement_id, p_settlement_date, v_banks.COUNT, SYSDATE);

  FORALL i IN 1..v_banks.COUNT
    INSERT INTO settlement_entries
      (settlement_id, bank_id, gross_send, gross_receive, net_position, entry_date)
    VALUES
      (v_settlement_id, v_banks(i).bank_id, v_banks(i).gross_send,
       v_banks(i).gross_receive, v_banks(i).net_position, p_settlement_date);

  FORALL i IN 1..v_banks.COUNT
    UPDATE bank_settlement_accounts
    SET current_balance = current_balance + v_banks(i).net_position,
        last_settled    = p_settlement_date
    WHERE bank_id = v_banks(i).bank_id;

  UPDATE interbank_transactions
  SET settled = 'Y', settled_at = SYSDATE, settlement_id = v_settlement_id
  WHERE settlement_date = p_settlement_date AND settled = 'N';
  COMMIT;
END;

CREATE OR REPLACE PROCEDURE recalculate_supply_chain_costs(
  p_vendor_id  NUMBER,
  p_cost_model VARCHAR2
) AS
  v_sql        VARCHAR2(32767);
  v_multiplier NUMBER;
  v_count      NUMBER := 0;
  v_err_count  NUMBER := 0;
  TYPE t_pid   IS TABLE OF NUMBER;
  TYPE t_cost  IS TABLE OF NUMBER;
  v_pids    t_pid;
  v_costs   t_cost;
  e_invalid_model EXCEPTION;
BEGIN
  IF p_cost_model NOT IN ('standard','weighted','marginal') THEN
    RAISE e_invalid_model;
  END IF;

  IF p_cost_model = 'standard' THEN
    v_multiplier := 1.0;
  ELSIF p_cost_model = 'weighted' THEN
    SELECT AVG(weight_factor) INTO v_multiplier
    FROM cost_model_weights WHERE model_name = 'weighted';
  ELSE
    v_multiplier := 1.15;
  END IF;

  v_sql := 'SELECT p.procurement_id, ' ||
           '       (p.unit_cost + NVL(s.handling_fee,0) + NVL(s.freight_cost,0)) * :mult ' ||
           ' FROM procurement_orders p ' ||
           ' JOIN supplier_charges s ON p.supplier_charge_id = s.charge_id ' ||
           ' WHERE p.vendor_id = :vid AND p.cost_recalc_flag = ''Y'' ' ||
           ' AND p.cost_model_applied <> :model';

  EXECUTE IMMEDIATE v_sql BULK COLLECT INTO v_pids, v_costs
  USING v_multiplier, p_vendor_id, p_cost_model;

  FORALL i IN 1..v_pids.COUNT SAVE EXCEPTIONS
    UPDATE procurement_orders
    SET recalculated_cost    = v_costs(i),
        cost_model_applied   = p_cost_model,
        recalc_timestamp     = SYSDATE
    WHERE procurement_id     = v_pids(i);

  v_count := SQL%ROWCOUNT;
  INSERT INTO cost_recalc_audit
    (vendor_id, cost_model, records_updated, run_at)
  VALUES (p_vendor_id, p_cost_model, v_count, SYSDATE);
  COMMIT;
EXCEPTION
  WHEN e_invalid_model THEN
    INSERT INTO cost_recalc_audit
      (vendor_id, cost_model, records_updated, error_msg, run_at)
    VALUES (p_vendor_id, p_cost_model, 0, 'Invalid cost model: '||p_cost_model, SYSDATE);
    COMMIT;
  WHEN OTHERS THEN
    v_err_count := SQL%BULK_EXCEPTIONS.COUNT;
    INSERT INTO cost_recalc_audit
      (vendor_id, cost_model, records_updated, error_msg, run_at)
    VALUES (p_vendor_id, p_cost_model, v_count, SQLERRM, SYSDATE);
    COMMIT;
    RAISE;
END;

CREATE OR REPLACE PROCEDURE generate_patient_billing_statements(
  p_billing_cycle_id NUMBER
) AS
  CURSOR c_patients IS
    SELECT DISTINCT patient_id FROM clinical_encounters
    WHERE billing_cycle_id = p_billing_cycle_id AND billed = 'N';
  CURSOR c_encounters(p_patient_id NUMBER) IS
    SELECT e.encounter_id, e.encounter_date, e.diagnosis_code,
           e.procedure_code, pr.unit_charge, e.units_performed,
           pr.unit_charge * e.units_performed AS line_total
    FROM clinical_encounters e
    JOIN procedure_rate_table pr ON e.procedure_code = pr.procedure_code
    WHERE e.patient_id = p_patient_id
    AND e.billing_cycle_id = p_billing_cycle_id
    AND e.billed = 'N';
  v_statement_id   NUMBER;
  v_stmt_total     NUMBER;
  v_stmt_count     NUMBER := 0;
  v_line_count     NUMBER := 0;
BEGIN
  FOR pat IN c_patients LOOP
    v_stmt_total := 0;
    SELECT NVL(MAX(statement_id),0)+1 INTO v_statement_id FROM billing_statements;

    INSERT INTO billing_statements
      (statement_id, patient_id, billing_cycle_id, statement_date, total_charges, status)
    VALUES (v_statement_id, pat.patient_id, p_billing_cycle_id, SYSDATE, 0, 'draft');

    FOR enc IN c_encounters(pat.patient_id) LOOP
      v_stmt_total := v_stmt_total + enc.line_total;
      INSERT INTO billing_statement_lines
        (statement_id, encounter_id, encounter_date, diagnosis_code,
         procedure_code, unit_charge, units, line_total)
      VALUES
        (v_statement_id, enc.encounter_id, enc.encounter_date, enc.diagnosis_code,
         enc.procedure_code, enc.unit_charge, enc.units_performed, enc.line_total);
      v_line_count := v_line_count + 1;
    END LOOP;

    UPDATE billing_statements
    SET total_charges = v_stmt_total, status = 'issued'
    WHERE statement_id = v_statement_id;

    UPDATE clinical_encounters
    SET billed = 'Y', statement_id = v_statement_id, billed_at = SYSDATE
    WHERE patient_id = pat.patient_id
    AND billing_cycle_id = p_billing_cycle_id
    AND billed = 'N';

    v_stmt_count := v_stmt_count + 1;
  END LOOP;

  INSERT INTO billing_cycle_summary
    (billing_cycle_id, statements_issued, total_lines, processed_at)
  VALUES (p_billing_cycle_id, v_stmt_count, v_line_count, SYSDATE);
  COMMIT;
END;

CREATE OR REPLACE PROCEDURE propagate_tariff_changes(
  p_tariff_code VARCHAR2,
  p_effective_date DATE
) AS
  v_rate         NUMBER;
  v_prev_rate    NUMBER;
  v_pct_change   NUMBER;
  v_category     VARCHAR2(50);
  v_sql          VARCHAR2(32767);
  v_affected     NUMBER := 0;
  TYPE t_sku_list IS TABLE OF VARCHAR2(50);
  v_skus t_sku_list;
BEGIN
  SELECT current_rate, previous_rate, product_category
  INTO v_rate, v_prev_rate, v_category
  FROM tariff_schedules
  WHERE tariff_code = p_tariff_code
  AND effective_date = p_effective_date;

  v_pct_change := ROUND((v_rate - v_prev_rate) / NULLIF(v_prev_rate, 0) * 100, 4);

  SELECT sku BULK COLLECT INTO v_skus
  FROM product_catalog
  WHERE product_category = v_category
  AND tariff_code = p_tariff_code;

  v_sql := 'UPDATE import_cost_components ' ||
           'SET duty_rate = :rate, ' ||
           '    landed_cost = unit_cost * (1 + :rate/100), ' ||
           '    tariff_updated_at = SYSDATE ' ||
           'WHERE sku IN (SELECT COLUMN_VALUE FROM TABLE(:sku_list)) ' ||
           'AND cost_source = ''import''';

  EXECUTE IMMEDIATE v_sql USING v_rate, v_rate, v_skus;
  v_affected := SQL%ROWCOUNT;

  FORALL i IN 1..v_skus.COUNT
    INSERT INTO tariff_impact_log
      (tariff_code, sku, old_rate, new_rate, pct_change, applied_at)
    VALUES
      (p_tariff_code, v_skus(i), v_prev_rate, v_rate, v_pct_change, SYSDATE);

  UPDATE tariff_schedules
  SET propagation_status = 'done',
      skus_affected = v_affected,
      propagated_at = SYSDATE
  WHERE tariff_code = p_tariff_code
  AND effective_date = p_effective_date;
  COMMIT;
EXCEPTION
  WHEN NO_DATA_FOUND THEN
    INSERT INTO tariff_error_log (tariff_code, error_msg, logged_at)
    VALUES (p_tariff_code, 'Tariff schedule not found', SYSDATE);
    COMMIT;
END;

CREATE OR REPLACE PROCEDURE run_fraud_detection_sweep(
  p_detection_date DATE,
  p_sensitivity     VARCHAR2 DEFAULT 'medium'
) AS
  v_velocity_limit  NUMBER;
  v_amount_limit    NUMBER;
  v_rule_version    VARCHAR2(20);
  TYPE t_txn_rec IS RECORD (
    account_id   NUMBER,
    txn_count    NUMBER,
    total_amount NUMBER,
    max_single   NUMBER
  );
  TYPE t_txn_tab IS TABLE OF t_txn_rec;
  v_suspicious t_txn_tab;
  v_case_id    NUMBER;
BEGIN
  SELECT velocity_limit, amount_limit, rule_version
  INTO v_velocity_limit, v_amount_limit, v_rule_version
  FROM fraud_detection_rules
  WHERE sensitivity = p_sensitivity AND active_flag = 'Y'
  AND ROWNUM = 1
  ORDER BY created_at DESC;

  SELECT account_id, COUNT(*), SUM(txn_amount), MAX(txn_amount)
  BULK COLLECT INTO v_suspicious
  FROM payment_transactions
  WHERE txn_date = p_detection_date AND flagged = 'N'
  GROUP BY account_id
  HAVING COUNT(*) > v_velocity_limit OR MAX(txn_amount) > v_amount_limit;

  SELECT NVL(MAX(case_id),0)+1 INTO v_case_id FROM fraud_cases;

  FORALL i IN 1..v_suspicious.COUNT
    INSERT INTO fraud_cases
      (case_id, account_id, detection_date, txn_count,
       total_amount, max_single_txn, sensitivity, rule_version,
       case_status, opened_at)
    VALUES
      (v_case_id + i - 1, v_suspicious(i).account_id, p_detection_date,
       v_suspicious(i).txn_count, v_suspicious(i).total_amount,
       v_suspicious(i).max_single, p_sensitivity, v_rule_version,
       'open', SYSDATE);

  FORALL i IN 1..v_suspicious.COUNT
    UPDATE payment_transactions
    SET flagged = 'Y', fraud_case_ref = v_case_id + i - 1
    WHERE account_id = v_suspicious(i).account_id
    AND txn_date     = p_detection_date;

  INSERT INTO fraud_sweep_log
    (detection_date, sensitivity, rule_version, cases_opened, run_at)
  VALUES (p_detection_date, p_sensitivity, v_rule_version, v_suspicious.COUNT, SYSDATE);
  COMMIT;
EXCEPTION
  WHEN NO_DATA_FOUND THEN
    INSERT INTO fraud_sweep_log
      (detection_date, sensitivity, rule_version, cases_opened, error_msg, run_at)
    VALUES (p_detection_date, p_sensitivity, NULL, 0, 'No active rule found', SYSDATE);
    COMMIT;
END;

CREATE OR REPLACE PROCEDURE age_warehouse_inventory(
  p_warehouse_id  NUMBER,
  p_as_of_date    DATE
) AS
  TYPE t_sku     IS TABLE OF VARCHAR2(100);
  TYPE t_days    IS TABLE OF NUMBER;
  TYPE t_qty     IS TABLE OF NUMBER;
  TYPE t_tier    IS TABLE OF VARCHAR2(20);
  v_skus    t_sku;
  v_days    t_days;
  v_qtys    t_qty;
  v_tiers   t_tier;
  v_write_offs  NUMBER := 0;
  v_provision   NUMBER := 0;
BEGIN
  SELECT i.sku,
         p_as_of_date - i.received_date,
         i.quantity_on_hand,
         CASE
           WHEN p_as_of_date - i.received_date > 365 THEN 'write_off'
           WHEN p_as_of_date - i.received_date > 180 THEN 'slow_moving'
           WHEN p_as_of_date - i.received_date > 90  THEN 'aging'
           ELSE 'current'
         END
  BULK COLLECT INTO v_skus, v_days, v_qtys, v_tiers
  FROM warehouse_inventory i
  WHERE i.warehouse_id = p_warehouse_id
  AND i.inventory_status <> 'aged';

  FORALL i IN 1..v_skus.COUNT
    UPDATE warehouse_inventory
    SET days_on_hand     = v_days(i),
        aging_tier       = v_tiers(i),
        inventory_status = CASE WHEN v_tiers(i) = 'write_off' THEN 'aged' ELSE inventory_status END,
        aged_at          = CASE WHEN v_tiers(i) = 'write_off' THEN SYSDATE ELSE aged_at END,
        last_aged_calc   = SYSDATE
    WHERE sku = v_skus(i) AND warehouse_id = p_warehouse_id;

  SELECT SUM(CASE WHEN v_tiers(LEVEL) = 'write_off'   THEN v_qtys(LEVEL) ELSE 0 END),
         SUM(CASE WHEN v_tiers(LEVEL) IN ('slow_moving','aging') THEN v_qtys(LEVEL) ELSE 0 END)
  INTO v_write_offs, v_provision
  FROM DUAL
  CONNECT BY LEVEL <= v_skus.COUNT;

  INSERT INTO inventory_aging_report
    (warehouse_id, as_of_date, write_off_units, provision_units, total_skus, run_at)
  VALUES
    (p_warehouse_id, p_as_of_date, v_write_offs, v_provision, v_skus.COUNT, SYSDATE);
  COMMIT;
EXCEPTION
  WHEN OTHERS THEN
    ROLLBACK;
    INSERT INTO aging_error_log (warehouse_id, error_msg, logged_at)
    VALUES (p_warehouse_id, SQLERRM, SYSDATE);
    COMMIT;
    RAISE;
END;

CREATE OR REPLACE PROCEDURE reconcile_broker_trade_confirmations(
  p_trade_date   DATE,
  p_broker_id    NUMBER
) AS
  v_matched      NUMBER := 0;
  v_unmatched    NUMBER := 0;
  v_broke_id     NUMBER;
  v_run_id       NUMBER;
  CURSOR c_internal IS
    SELECT trade_id, instrument_id, quantity, trade_price, direction
    FROM internal_trade_blotter
    WHERE trade_date = p_trade_date
    AND broker_id   = p_broker_id
    AND recon_status = 'pending';
  v_ext_qty    NUMBER;
  v_ext_price  NUMBER;
  v_tolerance  NUMBER := 0.001;
BEGIN
  SELECT NVL(MAX(run_id),0)+1 INTO v_run_id FROM recon_run_log;
  INSERT INTO recon_run_log (run_id, trade_date, broker_id, started_at, status)
  VALUES (v_run_id, p_trade_date, p_broker_id, SYSDATE, 'running');

  FOR int_rec IN c_internal LOOP
    BEGIN
      SELECT quantity, trade_price INTO v_ext_qty, v_ext_price
      FROM broker_trade_confirmations
      WHERE instrument_id = int_rec.instrument_id
      AND trade_date      = p_trade_date
      AND broker_id       = p_broker_id
      AND direction       = int_rec.direction
      AND recon_matched   = 'N'
      AND ROWNUM          = 1;

      IF ABS(v_ext_qty - int_rec.quantity) <= v_tolerance
         AND ABS(v_ext_price - int_rec.trade_price) <= v_tolerance THEN
        UPDATE internal_trade_blotter SET recon_status = 'matched' WHERE trade_id = int_rec.trade_id;
        UPDATE broker_trade_confirmations SET recon_matched = 'Y'
        WHERE instrument_id = int_rec.instrument_id
        AND trade_date = p_trade_date AND broker_id = p_broker_id
        AND direction  = int_rec.direction AND recon_matched = 'N' AND ROWNUM = 1;
        v_matched := v_matched + 1;
      ELSE
        INSERT INTO recon_breaks
          (run_id, trade_id, instrument_id, int_qty, ext_qty, int_price, ext_price, break_type, detected_at)
        VALUES
          (v_run_id, int_rec.trade_id, int_rec.instrument_id,
           int_rec.quantity, v_ext_qty, int_rec.trade_price, v_ext_price,
           CASE WHEN ABS(v_ext_qty - int_rec.quantity) > v_tolerance THEN 'qty_break' ELSE 'price_break' END,
           SYSDATE);
        v_unmatched := v_unmatched + 1;
      END IF;
    EXCEPTION
      WHEN NO_DATA_FOUND THEN
        INSERT INTO recon_breaks
          (run_id, trade_id, instrument_id, int_qty, int_price, break_type, detected_at)
        VALUES
          (v_run_id, int_rec.trade_id, int_rec.instrument_id,
           int_rec.quantity, int_rec.trade_price, 'missing_confirm', SYSDATE);
        v_unmatched := v_unmatched + 1;
    END;
  END LOOP;

  UPDATE recon_run_log
  SET matched_count = v_matched, unmatched_count = v_unmatched,
      status = 'completed', completed_at = SYSDATE
  WHERE run_id = v_run_id;
  COMMIT;
END;

CREATE PROCEDURE GetSensorReadingsByDeviceAndDateRange
    @DeviceID NVARCHAR(50),
    @FromDate DATETIME,
    @ToDate DATETIME
AS
BEGIN
    SELECT ReadingID, DeviceID, SensorType, ReadingValue, MeasurementUnit, RecordedAt, QualityFlag
    FROM IoTSensorReadings
    WHERE DeviceID = @DeviceID
      AND RecordedAt BETWEEN @FromDate AND @ToDate
    ORDER BY RecordedAt ASC;
END
